 23: 
 24: function makeTrend(overrides: Partial<MetricTrend> = {}): MetricTrend {
 25:   return {
 26:     direction: 'improving',
 27:     delta: 0.05,
 28:     previousValue: 0.80,
 29:     currentValue: 0.85,
 30:     percentChange: 6.25,
 31:     aggregation: 'avg',
 32:     ...overrides,
 33:   };
 34: }
 35: 
 36: function makeDynamics(overrides: Partial<MetricDynamics> = {}): MetricDynamics {
 37:   return {
 38:     featureVersion: '1.0',
 39:     velocity: 0.02,
 40:     acceleration: 0.001,
 41:     inflectionDetected: false,
 42:     projectedStatus: 'healthy',
 43:     confidence: 0.75,
 44:     ...overrides,
 45:   };
 46: }
 47: 
 48: function makeTrendBucket(overrides: Partial<TrendBucket> = {}): TrendBucket {
 49:   return {
 50:     startTime: '2026-02-20T00:00:00Z',
 51:     endTime: '2026-02-21T00:00:00Z',
 52:     count: 5,
 53:     avg: 0.82,
 54:     percentiles: { p10: 0.7, p25: 0.77, p50: 0.82, p75: 0.88, p90: 0.93 },
 55:     trend: null,
 56:     dynamics: null,
 57:     ...overrides,
 58:   };
 59: }
