 65: describe('Sparkline', () => {
 66:   it('renders null for fewer than 2 valid data points', () => {
 67:     const { container } = render(<Sparkline data={[0.5]} />);
 68:     expect(container.firstChild).toBeNull();
 69:   });
 70: 
 71:   it('renders null for empty data', () => {
 72:     const { container } = render(<Sparkline data={[]} />);
 73:     expect(container.firstChild).toBeNull();
 74:   });
 75: 
 76:   it('renders null when all values are null', () => {
 77:     const { container } = render(<Sparkline data={[null, null, null]} />);
 78:     expect(container.firstChild).toBeNull();
 79:   });
 80: 
 81:   it('renders SVG with polyline when 2+ valid values', () => {
 82:     const { container } = render(<Sparkline data={[0.5, 0.7, 0.9]} />);
 83:     const svg = container.querySelector('svg');
 84:     expect(svg).not.toBeNull();
 85:     const polyline = container.querySelector('polyline');
 86:     expect(polyline).not.toBeNull();
 87:     const points = polyline!.getAttribute('points');
 88:     expect(points).toBeTruthy();
 89:     expect(points!.split(' ')).toHaveLength(3);
 90:   });
 91: 
 92:   it('handles null gaps — excludes them from polyline points', () => {
 93:     const { container } = render(<Sparkline data={[0.5, null, 0.9]} />);
 94:     const polyline = container.querySelector('polyline');
 95:     expect(polyline).not.toBeNull();
 96:     // Only 2 valid values, so polyline has 2 points
 97:     expect(polyline!.getAttribute('points')!.split(' ')).toHaveLength(2);
 98:   });
