221:     });
222:     render(<TrendChart trend={makeTrend()} dynamics={dynamics} metricName="relevance" />);
223:     expect(screen.getByText('3.0d')).toBeInTheDocument();
224:   });
225: 
226:   it('shows confidence percentage', () => {
227:     render(<TrendChart trend={makeTrend()} dynamics={makeDynamics({ confidence: 0.75 })} metricName="relevance" />);
228:     expect(screen.getByText('Confidence:')).toBeInTheDocument();
229:     expect(screen.getByText('75%')).toBeInTheDocument();
230:   });
231: 
232:   // Y-domain: when previousValue === currentValue, yPad falls back to 0.05 (TrendChart.tsx:86)
233:   // This must render the chart container, not the "Insufficient data" fallback
234:   it('renders chart (not empty state) when previous and current values are equal (flat trend)', () => {
235:     const flatTrend = makeTrend({ previousValue: 0.8, currentValue: 0.8, delta: 0 });
236:     render(<TrendChart trend={flatTrend} metricName="relevance" />);
237:     expect(screen.getByLabelText('Trend chart for relevance')).toBeInTheDocument();
238:     expect(screen.queryByText('No trend data available')).toBeNull();
239:     expect(screen.queryByText('Insufficient data')).toBeNull();
240:   });
241: 
242:   // Y-domain: chart handles threshold values in domain calculation
243:   it('renders without error when warningThreshold and criticalThreshold provided', () => {
244:     expect(() =>
245:       render(
246:         <TrendChart
247:           trend={makeTrend()}
248:           warningThreshold={0.7}
249:           criticalThreshold={0.5}
250:           metricName="relevance"
251:         />,
252:       ),
253:     ).not.toThrow();
254:   });
