 36: function makeAlert(overrides: Partial<TriggeredAlert> = {}): TriggeredAlert {
 37:   return {
 38:     severity: 'warning',
 39:     message: 'Test alert message',
 40:     aggregation: 'avg',
 41:     threshold: 0.7,
 42:     actualValue: 0.6,
 43:     direction: 'below',
 44:     ...overrides,
 45:   };
 46: }
 47: 
 48: function makeSLA(overrides: Partial<SLAComplianceResult> = {}): SLAComplianceResult {
 49:   return {
 50:     sla: { metric: 'relevance', aggregation: 'avg', target: 0.8, direction: 'above' },
 51:     compliant: true,
 52:     status: 'compliant',
 53:     actualValue: 0.9,
 54:     gap: 0.1,
 55:     marginPercent: 12.5,
 56:     ...overrides,
 57:   };
 58: }
