63: export function RoleGate({ feature, children }: {
64:   feature: keyof RoleFeatureConfig;
65:   children: ReactNode;
66: }) {
67:   const { hasFeature } = useRole();
68:   return hasFeature(feature) ? <>{children}</> : null;
