 3: 
 4: interface SplitPaneProps {
 5:   left: ReactNode;
 6:   right: ReactNode;
 7:   initialSplit?: number;
 8:   minPct?: number;
 9:   maxPct?: number;
10: }
11: 
12: export function SplitPane({ left, right, initialSplit = 50, minPct = 25, maxPct = 75 }: SplitPaneProps) {
13:   const [splitPct, setSplitPct] = useState(initialSplit);
14:   const containerRef = useRef<HTMLDivElement>(null);
15:   const dragging = useRef(false);
16: 
17:   const onMouseDown = useCallback(() => { dragging.current = true; }, []);
18: 
19:   useEffect(() => {
20:     function onMouseMove(e: MouseEvent) {
21:       if (!dragging.current || !containerRef.current) return;
22:       const rect = containerRef.current.getBoundingClientRect();
23:       const pct = ((e.clientX - rect.left) / rect.width) * 100;
24:       setSplitPct(Math.max(minPct, Math.min(maxPct, pct)));
25:     }
26:     function onMouseUp() { dragging.current = false; }
27:     document.addEventListener('mousemove', onMouseMove);
28:     document.addEventListener('mouseup', onMouseUp);
29:     return () => {
30:       document.removeEventListener('mousemove', onMouseMove);
31:       document.removeEventListener('mouseup', onMouseUp);
32:     };
33:   }, [minPct, maxPct]);
34: 
35:   return (
36:     <div ref={containerRef} className="d-flex w-full" style={{ minHeight: SPLIT_PANE_MIN_HEIGHT }}>
37:       <div style={{ width: `${splitPct}%`, overflow: 'auto' }}>{left}</div>
38:       <div
39:         className="shrink-0" role="separator"
40:         aria-orientation="vertical"
41:         aria-valuenow={Math.round(splitPct)}
42:         aria-valuemin={minPct}
43:         aria-valuemax={maxPct}
44:         aria-label="Resize panes"
45:         tabIndex={0}
46:         onMouseDown={onMouseDown}
47:         onKeyDown={(e) => {
48:           if (e.key === 'ArrowLeft') { e.preventDefault(); setSplitPct(p => Math.max(minPct, p - 2)); }
49:           if (e.key === 'ArrowRight') { e.preventDefault(); setSplitPct(p => Math.min(maxPct, p + 2)); }
50:         }}
51:         style={{
52:           width: SPLIT_PANE_DIVIDER_WIDTH,
53:           cursor: 'col-resize',
54:           background: 'var(--border)',
55:           borderRadius: 'var(--radius-bar)',
56:         }}
57:       />
58:       <div style={{ width: `${100 - splitPct}%`, overflow: 'auto' }}>{right}</div>
59:     </div>
60:   );
61: } 1: import { useQuery } from '@tanstack/react-query';
