 97:   }
 98:   const offsetResult = OffsetSchema.safeParse(c.req.query('offset'));
 99:   if (!offsetResult.success) {
100:     return c.json({ error: 'Invalid offset. Must be non-negative integer.' }, HttpStatus.BadRequest);
101:   }
102:   const sortByResult = SortBySchema.safeParse(c.req.query('sortBy'));
103:   if (!sortByResult.success) {
104:     return c.json({ error: 'Invalid sortBy. Must be score_asc, score_desc, or timestamp_desc.' }, HttpStatus.BadRequest);
105:   }
106:   const scoreLabelResult = ScoreLabelSchema.safeParse(c.req.query('scoreLabel') || undefined);
107:   if (!scoreLabelResult.success) {
108:     return c.json({ error: 'Invalid scoreLabel. Max 100 characters.' }, HttpStatus.BadRequest);
109:   }
110:   const scoreLabel = scoreLabelResult.data;
111: 
112:   try {
113:     const now = new Date();
114:     const periodMs = PERIOD_MS[periodResult.data] ?? PERIOD_MS['7d'];
115:     const start = new Date(now.getTime() - periodMs);
116: 
117:     let evaluations = await loadEvaluationsForMetric(name, start.toISOString(), now.toISOString());
118: 
119:     if (scoreLabel) {
