25:         if (!cancelled) {
26:           setData(json);
27:           setError(null);
28:         }
29:       } catch (err) {
30:         if (!cancelled) {
31:           setError(err instanceof Error ? err : new Error(String(err)));
32:         }
33:       } finally {
34:         if (!cancelled) setIsLoading(false);
35:       }
36:     }
37: 
38:     function startPolling() {
39:       fetchLive();
40:       timerRef.current = setInterval(fetchLive, POLL_INTERVAL_MS);
41:     }
42: 
43:     function stopPolling() {
44:       if (timerRef.current) {
45:         clearInterval(timerRef.current);
46:         timerRef.current = null;
47:       }
48:     }
49: 
50:     function handleVisibility() {
51:       if (document.visibilityState === 'visible') {
52:         startPolling();
53:       } else {
54:         stopPolling();
55:       }
56:     }
57: 
58:     startPolling();
59:     document.addEventListener('visibilitychange', handleVisibility);
60: 
61:     return () => {
62:       cancelled = true;
63:       stopPolling();
64:       document.removeEventListener('visibilitychange', handleVisibility);
65:     };
66:   }, []);
67: 
68:   return { data, isLoading, error };
