 53: dashboardRoutes.get('/dashboard', async (c) => {
 54:   const periodResult = PeriodSchema.safeParse(c.req.query('period'));
 55:   if (!periodResult.success) {
 56:     return c.json({ error: ErrorMessage.InvalidPeriod }, HttpStatus.BadRequest);
 57:   }
 58:   const roleResult = RoleSchema.optional().safeParse(c.req.query('role') || undefined);
 59:   if (!roleResult.success) {
 60:     return c.json({ error: ErrorMessage.InvalidRole }, HttpStatus.BadRequest);
 61:   }
 62: 
 63:   try {
 64:     const period = periodResult.data;
 65:     const role = roleResult.data;
 66:     const dates = computePeriodDates(period);
 67:     const evaluationsByMetric = await loadEvaluationsByMetric(dates.start, dates.end);
 68:     const dashboard = computeDashboardSummary(evaluationsByMetric, undefined, dates);
 69:     const cqi = computeCQI(dashboard.metrics);
 70: 
 71:     // Compute sparkline data (24 time buckets per metric)
 72:     const startMs = new Date(dates.start).getTime();
 73:     const endMs = new Date(dates.end).getTime();
 74:     const sparklines: Record<string, (number | null)[]> = {};
 75:     for (const [metricName, evals] of evaluationsByMetric) {
 76:       sparklines[metricName] = computeSparklineData(evals, startMs, endMs, 24);
 77:     }
 78: 
 79:     if (role) {
 80:       const view = computeRoleView(dashboard, role as RoleViewType);
 81:       if (role === 'executive') {
 82:         return c.json({ ...view, cqi, sparklines });
 83:       }
 84:       return c.json({ ...view, sparklines });
