 23: function ThresholdBar({ actual, threshold, direction }: {
 24:   actual: number;
 25:   threshold: number;
 26:   direction: 'above' | 'below';
 27: }) {
 28:   const max = Math.max(actual, threshold) * 1.2 || 1;
 29:   const actualPct = Math.max(0, Math.min((actual / max) * 100, 100));
 30:   const thresholdPct = Math.max(0, Math.min((threshold / max) * 100, 100));
 31:   const isViolating = direction === 'below' ? actual < threshold : actual > threshold;
 32: 
 33:   return (
 34:     <div className="threshold-bar" aria-label={`Actual: ${formatScore(actual)}, Threshold: ${formatScore(threshold)}`}>
 35:       <div
 36:         className="threshold-bar-fill"
 37:         style={{
 38:           width: `${actualPct}%`,
 39:           background: isViolating ? 'var(--status-critical)' : 'var(--status-healthy)',
 40:         }}
 41:       />
 42:       <div
 43:         className="threshold-bar-marker"
 44:         style={{ left: `${thresholdPct}%` }}
 45:         title={`Threshold: ${formatScore(threshold)}`}
 46:       />
 47:     </div>
 48:   );
 49: }
