 54:       <div className="alert-message">{alert.message}</div>
 55:       <div className="alert-meta text-secondary text-xs">
 56:         {alert.aggregation} = {formatScore(alert.actualValue)} (threshold: {formatScore(alert.threshold)})
 57:       </div>
 58: 
 59:       <ThresholdBar
