24: export const coverageRoutes = new Hono();
25: 
26: /**
27:  * GET /api/coverage
28:  * Returns coverage heatmap: metrics x inputs with gap identification.
29:  *
30:  * Query params:
31:  *   period: '24h' | '7d' | '30d' (default: '7d')
32:  *   inputKey: 'traceId' | 'sessionId' (default: 'traceId')
33:  */
34: coverageRoutes.get('/coverage', async (c) => {
35:   const periodResult = PeriodSchema.safeParse(c.req.query('period'));
36:   if (!periodResult.success) {
37:     return c.json({ error: ErrorMessage.InvalidPeriod }, HttpStatus.BadRequest);
38:   }
39:   const inputKeyResult = InputKeySchema.safeParse(c.req.query('inputKey'));
40:   if (!inputKeyResult.success) {
41:     return c.json({ error: 'Invalid inputKey. Must be traceId or sessionId.' }, HttpStatus.BadRequest);
42:   }
43: 
44:   try {
45:     const now = new Date();
46:     const period = periodResult.data;
47:     const periodMs = PERIOD_MS[period] ?? PERIOD_MS['7d'];
48:     const start = new Date(now.getTime() - periodMs);
49: 
50:     const allEvaluations = await loadEvaluationsByMetric(
51:       start.toISOString(),
52:       now.toISOString(),
53:     );
54:     const evaluationsByMetric = filterJudgeEvaluations(allEvaluations);
55: 
56:     const heatmap = computeCoverageHeatmap(evaluationsByMetric, {
57:       inputKey: inputKeyResult.data,
58:     });
59: 
60:     return c.json({ period, ...heatmap });
61:   } catch (err) {
62:     return c.json({ error: sanitizeErrorForResponse(err) }, HttpStatus.InternalServerError);
63:   }
