 13: // WCAG 2.1 contrast ratio formula anchors — these specific values are required by the algorithm.
 14: const CONTRAST_DARK = '#111';
 15: const CONTRAST_LIGHT = '#fff';
 16: 
 17: const SHORT_NAMES: Record<string, string> = {
 18:   faithfulness: 'Faith',
 19:   relevance: 'Relev',
 20:   coherence: 'Coher',
 21:   safety: 'Safety',
 22:   instruction_adherence: 'Instr',
 23:   tool_accuracy: 'Tool',
 24:   latency: 'Latency',
 25: };
 26: 
 27: function shortName(metric: string): string {
 28:   return SHORT_NAMES[metric] ?? metric.slice(0, 6);
 29: }
 30: 
 31: /**
 32:  * Returns black or white text for WCAG 4.5:1 contrast against the
 33:  * interpolateRdYlGn background color for a given pearsonR value.
 34:  * Uses relative luminance per WCAG 2.1 contrast ratio formula.
 35:  */
 36: function contrastText(pearsonR: number): string {
 37:   const bg = colorScale(pearsonR);
 38:   // Parse "rgb(r, g, b)" string from d3
 39:   const m = bg.match(/(\d+)/g);
 40:   if (!m || m.length < 3) return CONTRAST_DARK;
 41:   const [r, g, b] = m.map(Number);
 42:   // sRGB relative luminance (WCAG 2.1)
 43:   const toLinear = (c: number) => {
 44:     const s = c / 255;
 45:     return s <= 0.03928 ? s / 12.92 : ((s + 0.055) / 1.055) ** 2.4;
 46:   };
 47:   const L = 0.2126 * toLinear(r) + 0.7152 * toLinear(g) + 0.0722 * toLinear(b);
 48:   // WCAG contrast ratio: (L1 + 0.05) / (L2 + 0.05)
 49:   // White text (#fff, L=1.0) needs ratio >= 4.5 → L_bg <= ~0.18
 50:   // Black text (#111, L≈0.012) needs ratio >= 4.5 → L_bg >= ~0.10
 51:   return L > 0.18 ? CONTRAST_DARK : CONTRAST_LIGHT;
 52: }
 53: 
 54: const colorScale = scaleSequential(interpolateRdYlGn).domain([-1, 1]);
 55: 
 56: function lookupCorrelation(
 57:   correlations: CorrelationFeature[],
 58:   a: string,
 59:   b: string,
 60: ): CorrelationFeature | undefined {
 61:   return correlations.find(
 62:     (c) => (c.metricA === a && c.metricB === b) || (c.metricA === b && c.metricB === a),
 63:   );
 64: }
