 77:         gridTemplateColumns: `${HEATMAP_ROW_HEADER_WIDTH}px repeat(${n}, 1fr)`,
 78:         gridTemplateRows: `${HEATMAP_COL_HEADER_HEIGHT}px repeat(${n}, 1fr)`,
 79:         aspectRatio: `${cols} / ${cols}`,
 80:       }}
 81:     >
 82:       {/* Top-left empty corner */}
 83:       <div role="cell" />
 84: 
 85:       {/* Column headers */}
 86:       {metrics.map((m) => (
 87:         <div
 88:           key={`col-${m}`}
 89:           role="columnheader"
 90:           className="text-secondary text-xs font-semibold truncate flex-center"
 91:           style={{
 92:           }}
 93:         >
 94:           {shortName(m)}
 95:         </div>
 96:       ))}
 97: 
 98:       {/* Rows */}
