  6: interface SpanNode {
  7:   spanId: string;
  8:   name: string;
  9:   durationMs?: number;
 10:   status?: { code: number; message?: string };
 11:   attributes?: Record<string, unknown>;
 12:   children: SpanNode[];
 13:   evalCount: number;
 14: }
 15: 
 16: interface SpanTreeProps {
 17:   spans: Array<{
 18:     spanId: string;
 19:     name: string;
 20:     durationMs?: number;
 21:     status?: { code: number; message?: string };
 22:     attributes?: Record<string, unknown>;
 23:     parentSpanId?: string;
 24:   }>;
 25:   evalsBySpan: Map<string, number>;
 26:   maxDuration: number;
 27: }
 28: 
 29: function buildTree(
 30:   spans: SpanTreeProps['spans'],
 31:   evalsBySpan: Map<string, number>,
 32: ): SpanNode[] {
 33:   const nodeMap = new Map<string, SpanNode>();
 34:   const roots: SpanNode[] = [];
 35: 
 36:   for (const s of spans) {
 37:     nodeMap.set(s.spanId, {
 38:       spanId: s.spanId,
 39:       name: s.name,
 40:       durationMs: s.durationMs,
 41:       status: s.status,
 42:       attributes: s.attributes,
 43:       children: [],
 44:       evalCount: evalsBySpan.get(s.spanId) ?? 0,
 45:     });
 46:   }
 47: 
 48:   for (const s of spans) {
 49:     const node = nodeMap.get(s.spanId)!;
 50:     const parentId = (s as { parentSpanId?: string }).parentSpanId;
 51:     if (parentId && nodeMap.has(parentId)) {
 52:       nodeMap.get(parentId)!.children.push(node);
 53:     } else {
 54:       roots.push(node);
 55:     }
 56:   }
 57: 
 58:   return roots;
 59: }
