 61: const STATUS_ICONS: Record<number, string> = {
 62:   0: '',      // UNSET
 63:   1: '\u2713', // OK ✓
 64:   2: '\u2717', // ERROR ✗
 65: };
 66: 
 67: function SpanRow({ node, depth, maxDuration }: { node: SpanNode; depth: number; maxDuration: number }) {
 68:   const barPct = maxDuration > 0 && node.durationMs ? Math.min((node.durationMs / maxDuration) * 100, 100) : 0;
 69:   const statusCode = node.status?.code ?? 0;
 70:   const isError = statusCode === 2;
 71: 
 72:   const barStyle: CSSProperties = {
 73:     height: 'var(--space-1)',
 74:     width: `${barPct}%`,
 75:     background: isError ? 'var(--status-critical)' : 'var(--status-healthy)',
 76:     borderRadius: 'var(--radius-xs)',
 77:     marginTop: 'var(--space-1)',
 78:     minWidth: barPct > 0 ? 'var(--space-0-5)' : 0,
 79:   };
 80: 
 81:   return (
 82:     <>
 83:       <div
 84:         className="flex-center gap-2 border-b"
 85:         style={{
 86:           paddingLeft: depth * SPAN_TREE_INDENT + SPAN_TREE_BASE_PADDING,
 87:           paddingTop: 'var(--space-2)',
 88:           paddingBottom: 'var(--space-2)',
 89:         }}
 90:       >
 91:         <span className="text-base" style={{ color: isError ? 'var(--status-critical)' : 'var(--text-primary)' }}>
 92:           {STATUS_ICONS[statusCode]}
 93:         </span>
 94:         <div className="flex-1">
 95:           <div className="text-xs font-medium">{node.name}</div>
 96:           <div className="flex-center gap-2">
 97:             <div className="flex-1" style={{ background: 'var(--bg-surface)', borderRadius: 'var(--radius-xs)', height: 'var(--space-1)' }}>
 98:               <div style={barStyle} />
 99:             </div>
100:             {node.durationMs != null && (
101:               <span className="mono-xs text-secondary nowrap">
102:                 {node.durationMs < 1000 ? `${node.durationMs.toFixed(0)}ms` : `${(node.durationMs / 1000).toFixed(2)}s`}
103:               </span>
104:             )}
105:           </div>
106:         </div>
107:         {node.evalCount > 0 && (
108:           <span className="text-2xs chip font-semibold chip-accent">
109:             {plural(node.evalCount, 'eval')}
110:           </span>
111:         )}
112:       </div>
113:       {node.children.map(child => (
114:         <SpanRow key={child.spanId} node={child} depth={depth + 1} maxDuration={maxDuration} />
115:       ))}
116:     </>
117:   );
118: }
