 6: interface PipelineHealth {
 7:   evalVolume: number;
 8:   lastEvalAge: string | null;
 9:   evalRate: string;
10: }
11: 
12: function computePipelineHealth(dashboard: QualityDashboardSummary): PipelineHealth {
13:   let totalSamples = 0;
14:   let latestTs: string | null = null;
15: 
16:   for (const m of dashboard.metrics) {
17:     totalSamples += m.sampleCount;
18:   }
19: 
20:   // Find most recent evaluation timestamp from worst explanations
21:   for (const m of dashboard.metrics) {
22:     const worst = (m as QualityDashboardSummary['metrics'][number] & { worstExplanation?: { timestamp?: string } }).worstExplanation;
23:     if (worst?.timestamp) {
24:       if (!latestTs || worst.timestamp > latestTs) latestTs = worst.timestamp;
25:     }
26:   }
27: 
28:   const lastEvalAge = latestTs ? formatTimestamp(latestTs) : null;
29: 
30:   // Compute rate based on period
31:   const period = dashboard.metrics[0]?.period;
32:   let periodHours = 168; // default 7d
33:   if (period) {
34:     const diffMs = new Date(period.end).getTime() - new Date(period.start).getTime();
35:     periodHours = Math.max(1, diffMs / (60 * 60 * 1000));
36:   }
37:   const perHour = totalSamples / periodHours;
38:   const evalRate = perHour >= 100 ? `${(perHour / 1000).toFixed(1)}k/hr`
39:     : perHour >= 1 ? `${perHour.toFixed(0)}/hr`
40:     : `${(perHour * 24).toFixed(1)}/day`;
41: 
42:   return { evalVolume: totalSamples, lastEvalAge, evalRate };
43: }
44: 
45: function formatVolume(n: number): string {
46:   if (n >= 10000) return `${(n / 1000).toFixed(1)}k`;
47:   if (n >= 1000) return `${(n / 1000).toFixed(1)}k`;
48:   return String(n);
49: }
