53:   const pipeline = computePipelineHealth(dashboard);
54: 
55:   const statusMessage = <>
56:     <span className="text-base">
57:       {overallStatus === 'healthy' && 'All metrics within thresholds'}
58:       {overallStatus === 'warning' && 'Some metrics need attention'}
59:       {overallStatus === 'critical' && 'Critical issues detected'}
60:       {overallStatus === 'no_data' && 'No evaluation data available'}
61:     </span>
62:     <div className="pipeline-stats d-flex gap-6">
63:       <div className="pipeline-stat flex-center">
64:         Eval Volume: <span className="stat-value">{formatVolume(pipeline.evalVolume)}</span>
65:       </div>
66:       <div className="pipeline-stat flex-center">
67:         Rate: <span className="stat-value">{pipeline.evalRate}</span>
68:       </div>
69:       {pipeline.lastEvalAge && (
70:         <div className="pipeline-stat flex-center">
71:           Last Eval: <span className="stat-value">{pipeline.lastEvalAge}</span>
72:         </div>
73:       )}
74:     </div>
75:   </>;
76: 
77:   return (
78:     <HealthBanner status={overallStatus} message={statusMessage}>
79:       <StatDisplay value={summary.totalMetrics} label="Total" />
80:       <StatDisplay value={summary.healthyMetrics} label="Healthy" valueClassName="text-healthy" />
81:       <StatDisplay value={summary.warningMetrics} label="Warning" valueClassName="text-warning" />
82:       <StatDisplay value={summary.criticalMetrics} label="Critical" valueClassName="text-critical" />
83:     </HealthBanner>
