 80: export function scoreColorBand(
 81:   value: number,
 82:   direction: ScoreDirection = 'maximize',
 83: ): ScoreColorBand {
 84:   const v = direction === 'minimize' ? 1 - value : value;
 85:   if (v >= 0.9) return 'excellent';
 86:   if (v >= 0.8) return 'good';
 87:   if (v >= 0.6) return 'adequate';
 88:   if (v >= 0.4) return 'poor';
 89:   return 'failing';
 90: }
