104: const LABEL_ORDINAL_MAP: Record<string, { ordinal: number; category: LabelFilterCategory }> = {
105:   excellent: { ordinal: 4, category: 'Pass' },
106:   highly_relevant: { ordinal: 4, category: 'Pass' },
107:   fully_faithful: { ordinal: 4, category: 'Pass' },
108:   perfect: { ordinal: 4, category: 'Pass' },
109:   relevant: { ordinal: 3, category: 'Pass' },
110:   good: { ordinal: 3, category: 'Pass' },
111:   faithful: { ordinal: 3, category: 'Pass' },
112:   pass: { ordinal: 3, category: 'Pass' },
113:   correct: { ordinal: 3, category: 'Pass' },
114:   coherent: { ordinal: 3, category: 'Pass' },
115:   partial: { ordinal: 2, category: 'Review' },
116:   borderline: { ordinal: 2, category: 'Review' },
117:   adequate: { ordinal: 2, category: 'Review' },
118:   mixed: { ordinal: 2, category: 'Review' },
119:   off_topic: { ordinal: 1, category: 'Fail' },
120:   irrelevant: { ordinal: 1, category: 'Fail' },
121:   unfaithful: { ordinal: 1, category: 'Fail' },
122:   fail: { ordinal: 1, category: 'Fail' },
123:   incorrect: { ordinal: 1, category: 'Fail' },
124:   incoherent: { ordinal: 1, category: 'Fail' },
125:   hallucinated: { ordinal: 0, category: 'Fail' },
