131: function normalizeLabel(label: string): string {
132:   return label.toLowerCase().replace(/-/g, '_').trim();
133: }
134: 
135: export function labelToOrdinal(label: string): LabelOrdinal {
136:   const normalized = normalizeLabel(label);
137:   const entry = LABEL_ORDINAL_MAP[normalized];
138:   if (entry) {
139:     return { ordinal: entry.ordinal, category: entry.category, mapped: true };
140:   }
141:   return { ordinal: 2, category: 'Review', mapped: false };
142: }
143: 
144: export function ordinalToCategory(ordinal: number): LabelFilterCategory {
145:   if (ordinal >= 3) return 'Pass';
146:   if (ordinal === 2) return 'Review';
147:   return 'Fail';
148: }
