201: // -- Path/byte formatters ---------------------------------------------------
202: 
203: export function shortPath(fullPath: string): string {
204:   const parts = fullPath.replace(/\\/g, '/').split('/');
205:   return parts.length > 3 ? `\u2026/${parts.slice(-3).join('/')}` : fullPath;
206: }
207: 
208: export function fmtBytes(n: number): string {
209:   if (n >= 1_000_000) return `${(n / 1_000_000).toFixed(1)}M`;
210:   if (n >= 1_000) return `${(n / 1_000).toFixed(1)}K`;
211:   return String(n);
212: }
213: 
214: // -- Timestamp formatting ---------------------------------------------------
215: 
216: export function formatTimestamp(ts: string): string {
217:   const d = new Date(ts);
218:   if (isNaN(d.getTime())) return ts || '-';
219:   const now = Date.now();
220:   const diffMs = now - d.getTime();
221:   const diffMin = Math.floor(diffMs / 60_000);
222:   if (diffMin < 1) return 'just now';
223:   if (diffMin < 60) return `${diffMin}m ago`;
224:   const diffHr = Math.floor(diffMin / 60);
225:   if (diffHr < 24) return `${diffHr}h ago`;
226:   const diffDay = Math.floor(diffHr / 24);
227:   if (diffDay < 7) return `${diffDay}d ago`;
228:   return d.toLocaleDateString();
