 22: interface TrendChartProps {
 23:   trend?: MetricTrend;
 24:   dynamics?: MetricDynamics;
 25:   warningThreshold?: number;
 26:   criticalThreshold?: number;
 27:   metricName: string;
 28: }
 29: 
 30: function formatValue(v: number): string {
 31:   return Math.abs(v) < 0.001 ? v.toExponential(2) : v.toFixed(4);
 32: }
 33: 
 34: function formatBreachTime(iso: string): string {
 35:   const hours = (new Date(iso).getTime() - Date.now()) / (1000 * 60 * 60);
 36:   if (hours <= 0) return 'threshold exceeded';
 37:   if (hours < 1) return `${Math.round(hours * 60)}m`;
 38:   if (hours < 48) return `${hours.toFixed(1)}h`;
 39:   return `${(hours / 24).toFixed(1)}d`;
 40: }
 41: 
 42: export function TrendChart({
 43:   trend,
 44:   dynamics,
 45:   warningThreshold,
 46:   criticalThreshold,
 47:   metricName,
 48: }: TrendChartProps) {
 49:   if (!trend) {
 50:     return <EmptyState message="No trend data available" />;
 51:   }
 52: 
 53:   // Build data points: previous and current
 54:   const data: Array<{ label: string; value: number; projected?: number }> = [
 55:     { label: 'Previous', value: trend.previousValue },
 56:     { label: 'Current', value: trend.currentValue },
 57:   ];
 58: 
 59:   // If dynamics has projectedBreachTime or velocity, add projection point
 60:   if (dynamics && dynamics.velocity !== 0) {
 61:     const projectedValue = trend.currentValue + dynamics.velocity;
 62:     data.push({
 63:       label: 'Projected',
 64:       value: trend.currentValue, // actual line ends here
 65:       projected: projectedValue,
 66:     });
 67:     // Set current point's projected value to bridge the dashed line
 68:     data[1].projected = trend.currentValue;
 69:   }
 70: 
 71:   // Compute Y domain with some padding
 72:   const allValues = data.flatMap((d) => [d.value, d.projected].filter((v): v is number => v != null));
 73:   if (warningThreshold != null) allValues.push(warningThreshold);
 74:   if (criticalThreshold != null) allValues.push(criticalThreshold);
 75:   if (allValues.length === 0) {
 76:     return <EmptyState message="Insufficient data" />;
 77:   }
 78:   const yMin = Math.min(...allValues);
 79:   const yMax = Math.max(...allValues);
 80:   const yPad = (yMax - yMin) * 0.15 || 0.05;
 81: 
 82:   return (
 83:     <div>
 84:       <div role="img" aria-label={`Trend chart for ${metricName}`}>
 85:         <ResponsiveContainer width="100%" height={CHART_HEIGHT}>
 86:           <LineChart data={data} margin={CHART_MARGIN}>
 87:             <CartesianGrid {...CHART_GRID_PROPS} />
 88:             <XAxis
 89:               dataKey="label"
 90:               tick={CHART_AXIS_TICK}
 91:               stroke={CHART_COLORS.grid}
 92:             />
 93:             <YAxis
 94:               domain={[yMin - yPad, yMax + yPad]}
 95:               tick={CHART_AXIS_TICK}
 96:               stroke={CHART_COLORS.grid}
 97:               tickFormatter={CHART_YAXIS_TICK_FORMATTER}
 98:               width={CHART_YAXIS_WIDTH}
 99:             />
100:             <Tooltip
101:               contentStyle={CHART_TOOLTIP_CONTENT_STYLE}
102:               formatter={(v: number | undefined) => [v != null ? formatValue(v) : 'N/A', '']}
103:               labelStyle={CHART_TOOLTIP_LABEL_STYLE}
104:             />
105:             {warningThreshold != null && (
106:               <ReferenceLine
107:                 y={warningThreshold}
108:                 stroke={CHART_COLORS.warning}
109:                 strokeDasharray={CHART_DASH_THRESHOLD}
110:                 label={{ value: 'Warning', fill: CHART_COLORS.warning, fontSize: CHART_AXIS_TICK.fontSize, position: 'right' }}
111:               />
112:             )}
113:             {criticalThreshold != null && (
114:               <ReferenceLine
115:                 y={criticalThreshold}
116:                 stroke={CHART_COLORS.critical}
117:                 strokeDasharray={CHART_DASH_THRESHOLD}
118:                 label={{ value: 'Critical', fill: CHART_COLORS.critical, fontSize: CHART_AXIS_TICK.fontSize, position: 'right' }}
119:               />
120:             )}
121:             <Line
122:               type="monotone"
123:               dataKey="value"
124:               stroke={CHART_COLORS.line}
125:               strokeWidth={CHART_STROKE_WIDTH}
126:               dot={{ fill: CHART_COLORS.line, r: CHART_DOT_RADIUS }}
127:               activeDot={{ r: CHART_DOT_RADIUS_ACTIVE }}
128:               connectNulls
129:             />
130:             {dynamics && dynamics.velocity !== 0 && (
131:               <Line
132:                 type="monotone"
133:                 dataKey="projected"
134:                 stroke={CHART_COLORS.line}
135:                 strokeWidth={CHART_STROKE_WIDTH}
136:                 strokeDasharray={CHART_DASH_PROJECTED}
137:                 dot={{ fill: CHART_COLORS.line, r: CHART_DOT_RADIUS_PROJECTED, strokeDasharray: '' }}
138:                 connectNulls
139:               />
140:             )}
141:           </LineChart>
142:         </ResponsiveContainer>
143:       </div>
144:       {dynamics && (
145:         <div className="flex-wrap text-xs gap-6 mt-2" style={{
146:           padding: 'var(--space-2) 0',
147:           color: CHART_COLORS.text,
148:         }}>
149:           <div>
150:             <span className="font-semibold">Velocity:</span>{' '}
151:             <span className="mono">
152:               {dynamics.velocity >= 0 ? '+' : ''}{formatValue(dynamics.velocity)}/hr
153:             </span>
154:           </div>
155:           <div>
156:             <span className="font-semibold">Acceleration:</span>{' '}
157:             <span className="mono">
158:               {dynamics.acceleration >= 0 ? '+' : ''}{formatValue(dynamics.acceleration)}/hr
159:             </span>
160:           </div>
161:           {dynamics.projectedBreachTime && (
162:             <div>
163:               <span className="font-semibold">Breach in:</span>{' '}
164:               <span className="mono" style={{
165:                 color: dynamics.projectedStatus === 'critical' ? CHART_COLORS.critical : CHART_COLORS.warning,
166:               }}>
167:                 {formatBreachTime(dynamics.projectedBreachTime)}
168:               </span>
169:             </div>
170:           )}
171:           <div>
172:             <span className="font-semibold">Confidence:</span>{' '}
173:             <span className="mono">
174:               {formatPercent(dynamics.confidence * 100, 0)}
175:             </span>
176:           </div>
177:         </div>
178:       )}
179:     </div>
180:   );
