 16: interface TrendSeriesProps {
 17:   data: TrendBucket[];
 18:   metricName: string;
 19: }
 20: 
 21: const TREND_COLORS = {
 22:   band: 'rgba(88, 166, 255, 0.1)',
 23:   bandStroke: 'rgba(88, 166, 255, 0.3)',
 24:   background: '#131920', // --bg-card; must be a hex literal for SVG fill attribute
 25: } as const;
 26: 
 27: function formatTime(iso: string, spanDays: number): string {
 28:   const d = new Date(iso);
 29:   if (spanDays <= 1) return d.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
 30:   if (spanDays <= 7) return d.toLocaleDateString([], { weekday: 'short', hour: '2-digit' });
 31:   return d.toLocaleDateString([], { month: 'short', day: 'numeric' });
 32: }
 33: 
 34: export function TrendSeries({ data, metricName }: TrendSeriesProps) {
 35:   if (data.length === 0) {
 36:     return <EmptyState message="No trend data available" />;
 37:   }
 38: 
 39:   const spanMs = new Date(data[data.length - 1].endTime).getTime() - new Date(data[0].startTime).getTime();
 40:   const spanDays = spanMs / (1000 * 60 * 60 * 24);
 41: 
 42:   const chartData = data.map((bucket) => ({
 43:     time: formatTime(bucket.startTime, spanDays),
 44:     avg: bucket.avg,
 45:     p10: bucket.percentiles?.p10 ?? null,
 46:     p50: bucket.percentiles?.p50 ?? null,
 47:     p90: bucket.percentiles?.p90 ?? null,
 48:     count: bucket.count,
 49:   }));
 50: 
 51:   const allVals = chartData.flatMap(d =>
 52:     [d.avg, d.p10, d.p90].filter((v): v is number => v !== null)
 53:   );
 54:   if (allVals.length === 0) {
 55:     return <EmptyState message="No scored evaluations in period" />;
 56:   }
 57: 
 58:   const yMin = Math.min(...allVals);
 59:   const yMax = Math.max(...allVals);
 60:   const yPad = (yMax - yMin) * 0.15 || 0.05;
 61: 
 62:   return (
 63:     <div role="img" aria-label={`Time series trend for ${metricName}`}>
 64:       <ResponsiveContainer width="100%" height={220}>
 65:         <ComposedChart data={chartData} margin={CHART_MARGIN}>
 66:           <CartesianGrid {...CHART_GRID_PROPS} />
 67:           <XAxis
 68:             dataKey="time"
 69:             tick={CHART_AXIS_TICK}
 70:             stroke={CHART_COLORS.grid}
 71:           />
 72:           <YAxis
 73:             domain={[yMin - yPad, yMax + yPad]}
 74:             tick={CHART_AXIS_TICK}
 75:             stroke={CHART_COLORS.grid}
 76:             tickFormatter={CHART_YAXIS_TICK_FORMATTER}
 77:             width={CHART_YAXIS_WIDTH}
 78:           />
 79:           <Tooltip
 80:             contentStyle={CHART_TOOLTIP_CONTENT_STYLE}
 81:             formatter={(v: number | string | undefined, name?: string) => [
 82:               formatScore(typeof v === 'number' ? v : null),
 83:               name === 'avg' ? 'Average' : (name ?? '').toUpperCase(),
 84:             ]}
 85:             labelStyle={CHART_TOOLTIP_LABEL_STYLE}
 86:           />
 87:           {/* P10-P90 band */}
 88:           <Area
 89:             type="monotone"
 90:             dataKey="p90"
 91:             stroke="none"
 92:             fill={TREND_COLORS.band}
 93:             connectNulls
 94:           />
 95:           <Area
 96:             type="monotone"
 97:             dataKey="p10"
 98:             stroke="none"
 99:             fill={TREND_COLORS.background}
100:             connectNulls
101:           />
102:           {/* P50 line */}
103:           <Line
104:             type="monotone"
105:             dataKey="p50"
106:             stroke={TREND_COLORS.bandStroke}
107:             strokeWidth={1}
108:             strokeDasharray="4 3"
109:             dot={false}
110:             connectNulls
111:           />
112:           {/* Average line */}
113:           <Line
114:             type="monotone"
115:             dataKey="avg"
116:             stroke={CHART_COLORS.line}
117:             strokeWidth={2}
118:             dot={{ fill: CHART_COLORS.line, r: 3 }}
119:             activeDot={{ r: 5 }}
120:             connectNulls
121:           />
122:         </ComposedChart>
123:       </ResponsiveContainer>
124:       <div className="flex-center justify-center gap-4 mt-1 text-xs" style={{ color: CHART_COLORS.text }}>
125:         <span><span style={{ color: CHART_COLORS.line }}>&#9473;</span> avg</span>
126:         <span><span className="opacity-50">- -</span> p50</span>
127:         <span><span style={{ opacity: 0.3 }}>&#9608;</span> p10-p90</span>
128:       </div>
129:     </div>
130:   );
