 48: const CATEGORY_COLORS: Record<LabelFilterCategory, string> = {
 49:   Pass: SCORE_COLORS.excellent,
 50:   Review: SCORE_COLORS.adequate,
 51:   Fail: SCORE_COLORS.failing,
 52: };
