 54: const labelSortFn: SortingFn<EvalRow> = (rowA, rowB) => {
 55:   const a = labelToOrdinal(rowA.original.label ?? 'unknown').ordinal;
 56:   const b = labelToOrdinal(rowB.original.label ?? 'unknown').ordinal;
 57:   return a - b;
 58: };
 59: 
 60: const categoryFilterFn: FilterFn<EvalRow> = (row, _id, filterValue: LabelFilterCategory[]) => {
 61:   if (!filterValue || filterValue.length === 0) return true;
 62:   const category = ordinalToCategory(labelToOrdinal(row.original.label ?? 'unknown').ordinal);
 63:   return filterValue.includes(category);
 64: };
