 68: const columns = [
 69:   columnHelper.display({
 70:     id: 'expand',
 71:     header: '',
 72:     cell: ({ row }) => (
 73:       <button
 74:         type="button"
 75:         className="cursor-pointer btn-reset"
 76:         onClick={row.getToggleExpandedHandler()}
 77:         aria-label={row.getIsExpanded() ? 'Collapse row' : 'Expand row'}
 78:         style={{ padding: 'var(--space-px) var(--space-1-5)' }}
 79:       >
 80:         <ExpandChevron expanded={row.getIsExpanded()} className="text-secondary text-xs" />
 81:       </button>
 82:     ),
 83:     size: EVAL_TABLE_EXPAND_COL_SIZE,
 84:   }),
 85:   columnHelper.accessor('score', {
 86:     header: 'Score',
 87:     cell: (info) => {
 88:       const row = info.row.original;
 89:       return (
 90:         <ScoreBadge
 91:           score={info.getValue()}
 92:           metricName="score"
 93:           label={formatScore(info.getValue())}
 94:           evaluator={row.evaluator}
 95:           evaluatorType={row.evaluatorType}
 96:           explanation={row.explanation}
 97:           traceId={row.traceId}
 98:         />
 99:       );
100:     },
101:     sortingFn: 'basic',
102:   }),
103:   columnHelper.accessor('label', {
104:     header: 'Label',
105:     cell: (info) => {
106:       const label = info.getValue() ?? 'unknown';
107:       const { category } = labelToOrdinal(label);
108:       return (
109:         <ColoredChip color={CATEGORY_COLORS[category]} className="font-medium">
110:           {label}
111:         </ColoredChip>
112:       );
113:     },
114:     sortingFn: labelSortFn,
115:     filterFn: categoryFilterFn,
116:   }),
117:   columnHelper.display({
118:     id: 'category',
119:     header: 'Category',
120:     cell: (info) => {
121:       const label = info.row.original.label ?? 'unknown';
122:       const category = ordinalToCategory(labelToOrdinal(label).ordinal);
123:       return (
124:         <ColoredChip color={CATEGORY_COLORS[category]} className="font-semibold">
125:           {category}
126:         </ColoredChip>
127:       );
128:     },
129:   }),
130:   columnHelper.accessor('explanation', {
