164: export function evalToRow(e: EvaluationResult): EvalRow {
165:   return {
166:     score: typeof e.scoreValue === 'number' ? e.scoreValue : 0,
167:     explanation: e.explanation,
168:     traceId: e.traceId,
169:     timestamp: e.timestamp,
170:     evaluator: e.evaluator,
171:     label: e.scoreLabel,
172:     evaluatorType: e.evaluatorType,
173:     spanId: e.spanId,
174:     sessionId: e.sessionId,
175:     agentName: e.agentName,
176:     trajectoryLength: e.trajectoryLength,
177:     stepScores: e.stepScores as EvalRow['stepScores'],
178:     toolVerifications: e.toolVerifications as EvalRow['toolVerifications'],
179:   };
180: }
