182: export function EvaluationTable({ evaluations }: { evaluations: EvalRow[] }) {
183:   const [sorting, setSorting] = useState<SortingState>([]);
184:   const [columnFilters, setColumnFilters] = useState<ColumnFiltersState>([]);
185:   const [activeCategories, setActiveCategories] = useState<LabelFilterCategory[]>([]);
186:   const [expanded, setExpanded] = useState<ExpandedState>({});
187: 
188:   const table = useReactTable({
189:     data: evaluations,
190:     columns,
191:     state: { sorting, columnFilters, expanded },
192:     onSortingChange: setSorting,
193:     onColumnFiltersChange: setColumnFilters,
194:     onExpandedChange: setExpanded,
195:     getRowCanExpand: () => true,
196:     getCoreRowModel: getCoreRowModel(),
197:     getSortedRowModel: getSortedRowModel(),
198:     getFilteredRowModel: getFilteredRowModel(),
199:     getExpandedRowModel: getExpandedRowModel(),
200:   });
201: 
202:   const toggleCategory = (cat: LabelFilterCategory) => {
203:     const next = activeCategories.includes(cat)
204:       ? activeCategories.filter((c) => c !== cat)
205:       : [...activeCategories, cat];
206:     setActiveCategories(next);
207:     setColumnFilters(
208:       next.length > 0 ? [{ id: 'label', value: next }] : [],
209:     );
210:   };
211: 
212:   const sortDir = (colId: string): 'ascending' | 'descending' | 'none' => {
213:     const s = sorting.find((entry) => entry.id === colId);
214:     if (!s) return 'none';
215:     return s.desc ? 'descending' : 'ascending';
216:   };
217: 
218:   return (
219:     <div>
220:       <div className="d-flex mb-3 gap-1-5">
221:         {(['Pass', 'Review', 'Fail'] as const).map((cat) => {
222:           const active = activeCategories.includes(cat);
223:           return (
224:             <button
225:               key={cat}
226:               type="button"
227:               onClick={() => toggleCategory(cat)}
228:               className="text-xs font-semibold cursor-pointer"
229:               style={{
230:                 padding: 'var(--space-1) var(--space-3)',
231:                 borderRadius: 'var(--radius)',
232:                 border: `1px solid ${CATEGORY_COLORS[cat]}`,
233:                 backgroundColor: active ? `${CATEGORY_COLORS[cat]}30` : 'transparent',
234:                 color: CATEGORY_COLORS[cat],
235:                 opacity: active ? 1 : EVAL_FILTER_INACTIVE_OPACITY,
236:                 transition: 'opacity var(--transition-fast), background-color var(--transition-fast)',
237:               }}
238:             >
239:               {cat}
240:             </button>
241:           );
242:         })}
243:       </div>
244:       <table className="data-table eval-table">
245:         <thead>
246:           {table.getHeaderGroups().map((hg) => (
247:             <tr key={hg.id}>
248:               {hg.headers.map((header) => {
249:                 const canSort = header.column.getCanSort();
250:                 return (
251:                   <th
252:                     key={header.id}
253:                     onClick={canSort ? header.column.getToggleSortingHandler() : undefined}
254:                     className="select-none"
255:                     style={{ cursor: canSort ? 'pointer' : 'default' }}
256:                     aria-sort={canSort ? sortDir(header.id) : undefined}
257:                   >
258:                     {flexRender(header.column.columnDef.header, header.getContext())}
259:                     {canSort && (
260:                       <span style={{ marginLeft: 'var(--space-1)', fontSize: 'var(--font-size-2xs)' }}>
261:                         {{ asc: ' ^', desc: ' v' }[header.column.getIsSorted() as string] ?? ''}
262:                       </span>
263:                     )}
264:                   </th>
265:                 );
266:               })}
267:             </tr>
268:           ))}
269:         </thead>
270:         <tbody>
271:           {table.getRowModel().rows.map((row) => (
272:             <Fragment key={row.id}>
273:               <tr className={row.getIsExpanded() ? 'eval-row-expanded' : ''}>
274:                 {row.getVisibleCells().map((cell) => (
275:                   <td key={cell.id}>
276:                     {flexRender(cell.column.columnDef.cell, cell.getContext())}
277:                   </td>
278:                 ))}
279:               </tr>
280:               {row.getIsExpanded() && (
281:                 <tr className="eval-expanded-panel">
282:                   <td colSpan={row.getVisibleCells().length}>
283:                     <EvaluationExpandedRow row={row.original} />
284:                   </td>
285:                 </tr>
286:               )}
287:             </Fragment>
288:           ))}
289:           {table.getRowModel().rows.length === 0 && (
290:             <tr>
291:               <td colSpan={table.getVisibleLeafColumns().length} className="text-muted text-center p-4">
292:                 No evaluations match the current filter.
293:               </td>
294:             </tr>
295:           )}
296:         </tbody>
297:       </table>
298:     </div>
299:   );
