 15: export function EvaluationDetailPage({ traceId }: { traceId: string }) {
 16:   const { data: allEvaluations, isLoading, error } = useTraceEvaluations(traceId);
 17: 
 18:   const search = useSearch();
 19:   const metricFilter = new URLSearchParams(search).get('metric');
 20: 
 21:   const evaluations = metricFilter && allEvaluations
 22:     ? allEvaluations.filter(ev => ev.evaluationName === metricFilter)
 23:     : allEvaluations;
 24: 
 25:   const heading = metricFilter
 26:     ? `${metricFilter} Evaluations`
 27:     : 'Trace Evaluations';
 28: 
 29:   return (
 30:     <PageShell isLoading={isLoading} error={error} skeletonHeight={SKELETON_HEIGHT_SM}>
 31:       {(!evaluations || evaluations.length === 0) ? (
 32:         <EmptyState
 33:           title="No Evaluations Found"
 34:           description={<>No evaluations found for trace <code>{traceId}</code></>}
 35:           showSyncHint
 36:         />
 37:       ) : (
 38:         <>
 39:           <DetailPageHeader title={heading} id={traceId}>
 40:             <span className="text-secondary text-xs">
 41:               {plural(evaluations.length, 'evaluation')}
 42:             </span>
 43:             <Link href={routes.trace(traceId)} className="text-xs link-accent">View trace &rarr;</Link>
 44:             {metricFilter && (
 45:               <Link
 46:                 href={routes.evaluationDetail(traceId)}
 47:                 className="text-xs link-accent"
 48:               >
 49:                 View all evaluations
 50:               </Link>
 51:             )}
 52:           </DetailPageHeader>
 53: 
 54:           {evaluations.map((ev, i) => (
 55:             <div key={`${ev.evaluationName}-${ev.timestamp}-${i}`} className="eval-detail-card card">
 56:               <div className="flex-center mb-3 justify-between">
 57:                 <div className="flex-center gap-3">
 58:                   <ScoreBadge
 59:                     score={ev.scoreValue ?? null}
 60:                     metricName={ev.evaluationName}
 61:                     label={ev.scoreLabel ?? (ev.scoreValue != null ? formatScore(ev.scoreValue) : undefined)}
 62:                   />
 63:                   <span className="text-base font-medium">{ev.evaluationName}</span>
 64:                 </div>
 65:                 <TimestampCell timestamp={ev.timestamp} className="text-secondary text-xs" />
 66:               </div>
 67: 
 68:               <ChainOfThoughtPanel
 69:                 explanation={ev.explanation}
 70:                 evaluator={ev.evaluator}
 71:               />
 72: 
 73:               {ev.stepScores && ev.stepScores.length > 0 && (
 74:                 <div className="mt-3">
 75:                   <div className="section-label mb-1">Step Scores</div>
 76:                   <div className="gap-1-5 mt-1 flex-wrap">
 77:                     {ev.stepScores.map(s => (
 78:                       <StepScoreChip key={`${s.step}`} step={s.step} score={s.score} explanation={s.explanation} />
 79:                     ))}
 80:                   </div>
 81:                 </div>
 82:               )}
 83: 
 84:               <details open className="mt-3">
 85:                 <summary className="cot-summary text-xs">Provenance &amp; Audit Trail</summary>
 86:                 <div style={{ paddingTop: 'var(--space-2)' }}>
 87:                   <ProvenancePanel
 88:                     evaluationName={ev.evaluationName}
 89:                     scoreValue={ev.scoreValue}
 90:                     scoreLabel={ev.scoreLabel}
 91:                     traceId={ev.traceId ?? traceId}
 92:                     spanId={ev.spanId}
 93:                     sessionId={ev.sessionId}
 94:                     timestamp={ev.timestamp}
 95:                     evaluator={ev.evaluator}
 96:                     evaluatorType={ev.evaluatorType}
 97:                     scoreUnit={ev.scoreUnit}
 98:                     agentName={ev.agentName}
 99:                     rawData={ev as unknown as Record<string, unknown>}
100:                   />
101:                 </div>
102:               </details>
103:             </div>
104:           ))}
105:         </>
106:       )}
107:     </PageShell>
108:   );
