 20: function errorRateColor(rate: number): string {
 21:   if (rate === 0) return 'var(--status-healthy)';
 22:   if (rate < ERROR_RATE_WARNING_THRESHOLD) return 'var(--status-warning)';
 23:   return 'var(--status-critical)';
