 31: export function AgentActivityPanel({ agents }: AgentActivityPanelProps) {
 32:   const [sort, setSort] = useState<SortKey>('invocations');
 33:   const [asc, setAsc] = useState(false);
 34:   const [expanded, setExpanded] = useState<string | null>(null);
 35: 
 36:   const colorIndex = useMemo(
 37:     () => Array.isArray(agents)
 38:       ? new Map(agents.map((a, i) => [a.agentName, AGENT_PALETTE[i % AGENT_PALETTE.length]]))
 39:       : new Map<string, string>(),
 40:     [agents],
 41:   );
 42: 
 43:   // React 18+ batches both setState calls in event handlers atomically
 44:   const toggleSort = useCallback((key: SortKey) => {
 45:     if (key === sort) {
 46:       setAsc(v => !v);
 47:     } else {
 48:       setSort(key);
 49:       setAsc(false);
 50:     }
 51:   }, [sort]);
 52: 
 53:   if (agents.length === 0) {
 54:     return <EmptyState message="No agent activity recorded for this period." />;
 55:   }
 56: 
 57:   const maxInvocations = Math.max(...agents.map(a => a.invocations), 1);
 58: 
 59:   const sorted = [...agents].sort((a, b) => {
 60:     const diff = a[sort] < b[sort] ? -1 : a[sort] > b[sort] ? 1 : 0;
 61:     return asc ? diff : -diff;
 62:   });
 63: 
 64:   const sortIndicator = (key: SortKey) =>
 65:     sort === key ? (asc ? ' \u2191' : ' \u2193') : '';
 66: 
 67:   return (
 68:     <div className="overflow-x-auto">
 69:       <table className="data-table sla-table" style={{ minWidth: AGENT_TABLE_MIN_WIDTH }}>
 70:         <thead>
 71:           <tr>
 72:             <th style={{ width: '30%' }}>Agent</th>
 73:             <th className="cursor-pointer select-none" onClick={() => toggleSort('invocations')}>
 74:               Invocations{sortIndicator('invocations')}
 75:             </th>
 76:             <th className="cursor-pointer select-none" onClick={() => toggleSort('errorRate')}>
 77:               Error Rate{sortIndicator('errorRate')}
 78:             </th>
 79:             <th className="cursor-pointer select-none" onClick={() => toggleSort('sessionCount')}>
 80:               Sessions{sortIndicator('sessionCount')}
 81:             </th>
 82:             <th className="cursor-pointer select-none" onClick={() => toggleSort('avgOutputSize')}>
 83:               Avg Output{sortIndicator('avgOutputSize')}
 84:             </th>
 85:             <th>Rate Limits</th>
 86:             <th>Source</th>
 87:           </tr>
 88:         </thead>
 89:         <tbody>
 90:           {sorted.map((agent) => {
 91:             const color = colorIndex.get(agent.agentName) ?? AGENT_PALETTE[0];
 92:             const errColor = errorRateColor(agent.errorRate);
 93:             const invPct = (agent.invocations / maxInvocations) * 100;
 94:             const topSource = Object.entries(agent.sourceTypes).sort((a, b) => b[1] - a[1])[0]?.[0];
 95:             const isExpanded = expanded === agent.agentName;
 96:             const hasLinks = agent.sessionIds.length > 0 || agent.traceIds.length > 0;
 97: 
 98:             return (
 99:               <Fragment key={agent.agentName}>
100:                 <tr
101:                   className={`valign-middle${isExpanded ? ' eval-row-expanded' : ''}`}
102:                   style={{ cursor: hasLinks ? 'pointer' : undefined }}
103:                   onClick={() => hasLinks && setExpanded(isExpanded ? null : agent.agentName)}
104:                 >
105:                   {/* Agent name with color accent */}
106:                   <td>
107:                     <div className="flex-center gap-2">
108:                       {hasLinks && (
109:                         <ExpandChevron expanded={isExpanded} className="text-2xs text-muted shrink-0" />
110:                       )}
111:                       <span className="dot-sm" style={{ background: color }} />
112:                       <span className="mono-xs text-primary break-all">
113:                         {agent.agentName}
114:                       </span>
115:                     </div>
116:                   </td>
117: 
118:                   {/* Invocations with inline bar */}
119:                   <td>
120:                     <div className="flex-center gap-2">
121:                       <span className="mono-xs" style={{ minWidth: 'var(--space-8)' }}>
122:                         {agent.invocations}
123:                       </span>
124:                       <BarIndicator value={invPct} color={color} opacity={0.7} className="flex-1" style={{ minWidth: AGENT_BAR_MIN_WIDTH }} />
125:                     </div>
126:                   </td>
127: 
128:                   {/* Error rate */}
129:                   <td>
130:                     <div className="flex-center gap-1-5">
131:                       <span className="mono-xs" style={{
132:                         color: errColor,
133:                       }}>
134:                         {agent.errors > 0 ? formatPercent(agent.errorRate * 100) : '\u2014'}
135:                       </span>
136:                       {agent.errors > 0 && (
137:                         <span className="text-muted text-xs">
138:                           ({agent.errors})
139:                         </span>
140:                       )}
141:                     </div>
142:                   </td>
143: 
144:                   {/* Session count */}
145:                   <td>
146:                     <span className="mono-xs">
147:                       {agent.sessionCount}
148:                     </span>
149:                   </td>
150: 
151:                   {/* Avg output size */}
152:                   <td>
153:                     <span className="mono-xs text-secondary">
154:                       {fmtBytes(agent.avgOutputSize)}
155:                     </span>
156:                   </td>
157: 
158:                   {/* Rate limits */}
159:                   <td>
160:                     {agent.rateLimitCount > 0 ? (
161:                       <span className="mono-xs badge-warning">
162:                         {agent.rateLimitCount}x
163:                       </span>
164:                     ) : (
165:                       <span className="text-muted text-xs">{'\u2014'}</span>
166:                     )}
167:                   </td>
168: 
169:                   {/* Source type */}
170:                   <td>
171:                     {topSource ? (
172:                       <span className="mono text-muted text-2xs uppercase">
173:                         {topSource}
174:                       </span>
175:                     ) : <span className="text-muted">{'\u2014'}</span>}
176:                   </td>
177:                 </tr>
178: 
179:                 {/* Expanded row: eval summary + sessions + traces */}
180:                 {isExpanded && (
181:                   <tr className="eval-expanded-panel">
182:                     <td colSpan={COLUMN_COUNT} className="border-b">
183:                       {/* Evaluation summary */}
184:                       <EvalSummaryRow evalSummary={agent.evalSummary} />
185: 
186:                       {/* Daily invocation sparkline */}
187:                       {agent.dailyCounts.length > 1 && agent.dailyCounts.some(v => v > 0) && (
188:                         <div className="border-b-subtle mb-1 pad-panel-section">
189:                           <div className="flex-center gap-3">
190:                             <div className="text-xs text-muted uppercase shrink-0">
191:                               Daily Activity
192:                             </div>
193:                             <Sparkline
194:                               data={agent.dailyCounts}
195:                               width={SPARKLINE_WIDTH}
196:                               height={SPARKLINE_HEIGHT}
197:                               color={colorIndex.get(agent.agentName) ?? AGENT_PALETTE[0]}
198:                               label={`Daily invocations for ${agent.agentName}`}
199:                             />
200:                             <span className="mono text-muted text-2xs shrink-0">
201:                               peak {Math.max(...agent.dailyCounts)}/day
202:                             </span>
203:                           </div>
204:                         </div>
205:                       )}
206: 
207:                       <div className="d-grid gap-4" style={{
208:                         gridTemplateColumns: '1fr 1fr',
209:                         padding: 'var(--space-3) 0 var(--space-1)',
210:                       }}>
211:                         {/* Sessions column */}
212:                         <div>
213:                           <div className="text-muted mb-1-5 text-xs uppercase">
214:                             Sessions ({agent.sessionCount})
215:                           </div>
216:                           <div className="flex-col gap-1">
217:                             {agent.sessionIds.map(sid => (
218:                               <TruncatedIdLink
219:                                 key={sid}
220:                                 id={sid}
221:                                 href={routes.session(sid)}
222:                                 maxLen={12}
223:                                 onClick={(e) => e.stopPropagation()}
224:                               />
225:                             ))}
226:                             {agent.sessionIds.length === 0 && (
227:                               <span className="text-muted text-xs">none</span>
228:                             )}
229:                             {/* sessionCount === total unique sessions; sessionIds is capped at 50 */}
230:                             {agent.sessionIdsTruncated && (
231:                               <span className="text-muted text-2xs italic">
232:                                 +{agent.sessionCount - agent.sessionIds.length} more
233:                               </span>
234:                             )}
235:                           </div>
236:                         </div>
237: 
238:                         {/* Traces column */}
239:                         <div>
240:                           <div className="text-muted mb-1-5 text-xs uppercase">
241:                             Traces ({agent.traceIdsTotal ?? agent.traceIds.length})
242:                           </div>
243:                           <div className="flex-col gap-1">
244:                             {agent.traceIds.map(tid => (
245:                               <TruncatedIdLink
246:                                 key={tid}
247:                                 id={tid}
248:                                 href={routes.trace(tid)}
249:                                 maxLen={12}
250:                                 onClick={(e) => e.stopPropagation()}
251:                               />
252:                             ))}
253:                             {agent.traceIds.length === 0 && (
254:                               <span className="text-muted text-xs">none</span>
255:                             )}
256:                             {agent.traceIdsTruncated && (
257:                               <span className="text-muted text-2xs italic">
258:                                 +{(agent.traceIdsTotal ?? 0) - agent.traceIds.length} more
259:                               </span>
260:                             )}
261:                           </div>
262:                         </div>
263:                       </div>
264:                     </td>
265:                   </tr>
266:                 )}
267:               </Fragment>
268:             );
269:           })}
270:         </tbody>
271:       </table>
272:     </div>
273:   );
274: }
