276: /** Per-agent evaluation metrics (relevance, coherence, faithfulness, etc.) */
277: function EvalSummaryRow({ evalSummary }: { evalSummary: Record<string, EvalMetricSummary> }) {
278:   const metrics = Object.entries(evalSummary);
279:   if (metrics.length === 0) {
280:     return (
281:       <div className="text-xs text-muted border-b-subtle mb-1 pad-panel-sparse">
282:         No evaluations linked to this agent.
283:       </div>
284:     );
285:   }
286: 
287:   return (
288:     <div className="border-b-subtle mb-1 pad-panel-section">
289:       <div className="text-muted mb-1-5 text-xs uppercase">
290:         Evaluation Metrics
291:       </div>
292:       <div className="flex-wrap gap-3">
293:         {metrics.map(([name, m]) => {
294:           const barColor = scoreColor(m.avg);
295:           return (
296:             <div key={name} style={{
297:               minWidth: AGENT_EVAL_CARD_MIN_WIDTH,
298:               padding: 'var(--space-2) var(--space-2-5)',
299:               background: 'var(--bg-card)',
300:               border: '1px solid var(--border-subtle)',
301:               borderRadius: 'var(--radius)',
302:             }}>
303:               <div className="text-secondary mb-1 text-xs truncate">
304:                 {name}
305:               </div>
306:               {/* Score bar */}
307:               <div className="flex-center mb-1 gap-2">
308:                 <BarIndicator value={Math.min(m.avg * 100, 100)} color={barColor} className="flex-1" />
309:                 <span className="mono-xs font-semibold text-right" style={{
310:                   color: barColor,
311:                   minWidth: 'var(--space-8)',
312:                 }}>
313:                   {m.avg.toFixed(2)}
314:                 </span>
315:               </div>
316:               {/* Min/max range + count */}
317:               <div className="mono text-muted flex-wrap justify-between text-2xs">
318:                 <span>{m.min.toFixed(2)}\u2013{m.max.toFixed(2)}</span>
319:                 <span>n={m.count}</span>
320:               </div>
321:             </div>
322:           );
323:         })}
324:       </div>
325:     </div>
326:   );
327: }
