329: /** Summary bar above the table -- totals at a glance */
330: export function AgentActivitySummary({ agents }: AgentActivityPanelProps) {
331:   const totalInvocations = agents.reduce((s, a) => s + a.invocations, 0);
332:   const totalErrors = agents.reduce((s, a) => s + a.errors, 0);
333:   const totalRateLimits = agents.reduce((s, a) => s + a.rateLimitCount, 0);
334:   const overallErrorRate = totalInvocations > 0 ? (totalErrors / totalInvocations) * 100 : 0;
335: 
336:   return (
337:     <div className="d-flex flex-wrap gap-8 surface-elevated mb-5" style={{
338:       padding: 'var(--space-4) var(--space-5)',
339:     }}>
340:       {[
341:         { label: 'Agents', value: agents.length },
342:         { label: 'Invocations', value: totalInvocations.toLocaleString() },
343:         {
344:           label: 'Error Rate',
345:           value: totalInvocations > 0 ? formatPercent(overallErrorRate) : '\u2014',
346:           color: overallErrorRate === 0
347:             ? 'var(--status-healthy)'
348:             : overallErrorRate < ERROR_RATE_WARNING_THRESHOLD * 100
349:               ? 'var(--status-warning)'
350:               : 'var(--status-critical)',
351:         },
352:         {
353:           label: 'Rate Limits',
354:           value: totalRateLimits > 0 ? totalRateLimits : '\u2014',
355:           color: totalRateLimits > 0 ? 'var(--status-warning)' : undefined,
356:         },
357:       ].map(({ label, value, color }) => (
358:         <StatDisplay key={label} value={value} label={label} valueColor={color} />
359:       ))}
360:     </div>
361:   );
