 33: export function SessionDetailPage({ sessionId }: { sessionId: string }) {
 34:   const { data, isLoading, error } = useSessionDetail(sessionId);
 35:   const isNotSynced = !isLoading && error instanceof SessionNotFoundError;
 36: 
 37:   if (isLoading || (!isNotSynced && error)) {
 38:     return <PageShell isLoading={isLoading} error={error ?? null} skeletonHeight={SKELETON_HEIGHT_LG}>{null}</PageShell>;
 39:   }
 40: 
 41:   if (isNotSynced) {
 42:     return (
 43:       <div>
 44:         <Link href="/" className="back-link inline-flex-center">&larr; Back to dashboard</Link>
 45:         <div className="card text-center" style={{ padding: 'var(--space-8) var(--space-6)' }}>
 46:           <div className="mono-xs mb-1-5 uppercase text-warning">Session Not Yet Available</div>
 47:           <div className="mono-xs text-secondary leading-relaxed" style={{
 48:             maxWidth: CALLOUT_MAX_WIDTH,
 49:             margin: '0 auto',
 50:           }}>
 51:             This session has not been synced to the dashboard KV store yet.
 52:             Data is synced periodically &mdash; check back after the next pipeline run.
 53:           </div>
 54:           <div className="mono-xs text-muted mt-3 break-all">{sessionId}</div>
 55:         </div>
 56:       </div>
 57:     );
 58:   }
 59: 
 60:   if (!data) return null;
 61: 
 62:   const {
 63:     dataSources, sessionInfo, timespan, toolUsage, mcpUsage,
 64:     agentActivity, fileAccess, gitCommits, tokenProgression, spanBreakdown,
 65:     alertSummary, codeStructure, errors,
 66:     multiAgentEvaluation, evaluations,
 67:   } = data;
 68: 
 69:   const si = sessionInfo ?? {
 70:     projectName: 'unknown', workingDirectory: '', gitRepository: '', gitBranch: '',
 71:     nodeVersion: '', resumeCount: 0, initialMessageCount: 0, initialContextTokens: 0,
 72:     finalMessageCount: 0, taskCount: 0, uncommittedAtStart: 0,
 73:   };
 74:   const spanCount = dataSources.traces.count;
 75:   const errorDetails = errors.details;
 76: 
 77:   // Derive computed values
 78:   const totalToolCalls = Object.values(toolUsage).reduce((a, b) => a + b, 0);
 79:   const totalMcpCalls = Object.values(mcpUsage).reduce((a, b) => a + b, 0);
 80:   const maxTokenSnapshot = tokenProgression.at(-1);
 81:   const maxToolCount = Math.max(...Object.values(toolUsage), 1);
 82:   const maxMcpCount = Math.max(...Object.values(mcpUsage), 1);
 83:   const maxFileCount = fileAccess[0]?.count ?? 1;
 84:   const maxSpanCount = Math.max(...Object.values(spanBreakdown), 1);
 85: 
 86:   // Issue detection
 87:   const hallucinationEvals = evaluations.filter(e =>
 88:     (e.evaluationName ?? '').toLowerCase().includes('hallucin') ||
 89:     ((e.scoreLabel ?? '').toLowerCase() === 'fail' && typeof e.scoreValue === 'number' && e.scoreValue < HALLUCINATION_SCORE_THRESHOLD)
 90:   );
 91:   const failedEvals = evaluations.filter(e =>
 92:     (e.scoreLabel ?? '').toLowerCase() === 'fail'
 93:   );
 94:   const errorCount = errorDetails.length;
 95:   const hasIssues = alertSummary.totalFired > 0 || errorCount > 0 ||
 96:     hallucinationEvals.length > 0 || failedEvals.length > 0;
 97:   const issueHealth: SectionHealth = errorCount > 0 || hallucinationEvals.length > 0
 98:     ? 'crit'
 99:     : alertSummary.totalFired > 0 || failedEvals.length > 0
100:     ? 'warn'
101:     : 'ok';
102: 
103:   // Score interpretation
104:   const evaluation = multiAgentEvaluation;
105:   const handoffScore = evaluation.handoffScore ?? 0;
106:   const avgRelevance = evaluation.avgTurnRelevance ?? 0;
107:   const completeness = evaluation.conversationCompleteness ?? 0;
108:   const evalRows: EvalRow[] = evaluations.map(evalToRow);
109: 
110:   // Unique models used
111:   const models = [...new Set(tokenProgression.map(t => t.model).filter(Boolean))];
112: 
113:   return (
114:     <div style={{ maxWidth: PAGE_CONTENT_MAX_WIDTH }}>
115:       <Link href="/" className="back-link inline-flex-center">&larr; Back to dashboard</Link>
116: 
117:       {/* ── Header ── */}
118:       <div style={{
119:         background: 'var(--bg-card)',
120:         border: '1px solid var(--border-subtle)',
121:         borderBottom: 'none',
122:         padding: 'var(--space-5) var(--space-6) var(--space-4)',
123:         marginBottom: 0,
124:       }}>
125:         <div className="flex-wrap gap-4 justify-between align-start">
126:           <div>
127:             <div className="mono text-muted mb-1-5 text-2xs uppercase">Session Detail</div>
128:             <div className="mono font-semibold text-base mb-2 break-all text-accent-hover" style={{
129:               letterSpacing: 'var(--letter-spacing-id)',
130:             }}>{sessionId}</div>
131:             <div className="text-secondary text-xs flex-wrap gap-4">
132:               <span>{si.projectName}</span>
133:               {si.gitRepository && (
134:                 <span className="text-muted">
135:                   {si.gitRepository}
136:                   {si.gitBranch ? ` · ${si.gitBranch}` : ''}
137:                 </span>
138:               )}
139:               {si.resumeCount > 1 && (
140:                 <span className="mono text-2xs chip uppercase" style={{
141:                   background: 'var(--accent-muted)',
142:                   color: 'var(--accent-hover)',
143:                 }}>RESUMED ×{si.resumeCount}</span>
144:               )}
145:               {models.map(m => (
146:                 <span key={m} className="mono text-2xs text-muted chip chip-badge">{m}</span>
147:               ))}
148:             </div>
149:             {timespan && (
150:               <div className="text-muted text-xs flex-wrap gap-4" style={{ marginTop: 'var(--space-1)' }}>
151:                 <span>{new Date(timespan.start).toLocaleString()}</span>
152:                 <span>&rarr;</span>
153:                 <span>{new Date(timespan.end).toLocaleString()}</span>
154:                 <span className="mono text-2xs chip chip-badge">{timespan.durationHours}h</span>
155:               </div>
156:             )}
157:           </div>
158:         </div>
159:       </div>
160: 
161:       {/* ── Vitals strip ── */}
162:       <div className="flex-wrap" style={{
163:         gap: 0,
164:         background: 'var(--bg-elevated)',
165:         border: '1px solid var(--border-subtle)',
166:         borderBottom: '1px solid var(--border)',
167:         padding: 'var(--space-3-5) var(--space-6)',
168:         rowGap: 'var(--space-3)',
169:         marginBottom: 'var(--space-0-5)',
170:       }}>
171:         <StatDisplay label="Spans" value={spanCount} />
172:         <div className="vitals-divider" />
173:         <StatDisplay label="Tool calls" value={totalToolCalls} />
174:         <div className="vitals-divider" />
175:         <StatDisplay label="MCP calls" value={totalMcpCalls} />
176:         <div className="vitals-divider" />
177:         <StatDisplay label="Commits" value={gitCommits.length} valueColor={gitCommits.length > 0 ? 'var(--status-healthy)' : undefined} />
178:         <div className="vitals-divider" />
179:         <StatDisplay label="Alerts fired" value={alertSummary.totalFired} valueColor={alertSummary.totalFired > 0 ? 'var(--status-warning)' : undefined} />
180:         <div className="vitals-divider" />
181:         <StatDisplay label="Errors" value={errorCount} valueColor={errorCount > 0 ? 'var(--status-critical)' : undefined} />
182:         {maxTokenSnapshot && (
183:           <>
184:             <div className="vitals-divider" />
185:             <StatDisplay label="Messages" value={maxTokenSnapshot.messages} />
186:             <div className="vitals-divider" />
187:             <StatDisplay label="Output tokens" value={fmtBytes(maxTokenSnapshot.outputTokens)} />
188:           </>
189:         )}
190:       </div>
191: 
192:       {/* ── Issues & Anomalies ── */}
193:       <Section
194:         title="Issues & Anomalies"
195:         badge={hasIssues ? `${[
196:           alertSummary.totalFired > 0 && `${alertSummary.totalFired} alerts`,
197:           errorCount > 0 && `${errorCount} errors`,
198:           hallucinationEvals.length > 0 && `${hallucinationEvals.length} hallucinations`,
199:           failedEvals.length > 0 && `${failedEvals.length} failures`,
200:         ].filter(Boolean).join(' · ')}` : 'clean'}
201:         health={issueHealth}
202:         defaultOpen={hasIssues}
203:       >
204:         {!hasIssues && (
205:           <div className="mono-xs text-healthy">
206:             No issues detected in this session.
207:           </div>
208:         )}
209: 
210:         {alertSummary.totalFired > 0 && (
211:           <IssueCallout severity="warning" title={`${plural(alertSummary.totalFired, 'alert')} fired across ${plural(alertSummary.stopEvents, 'stop event')}`}>
212:             <strong>task-completion-low</strong> — The task completion ratio fell below 0.85.
213:             This fires when tasks are created but not marked complete before the session ends.
214:             Common causes: work deferred to backlog, sub-tasks spawned but not resolved,
215:             or tasks marked in-progress but not completed within the session.
216:           </IssueCallout>
217:         )}
218: 
219:         {errorCount > 0 && (
220:           <IssueCallout severity="critical" title={plural(errorCount, 'error span')}>
221:             <div className="mb-2">Tool invocations or agent calls that reported errors:</div>
222:             <TruncatedList
223:               items={errorDetails}
224:               max={MAX_ERROR_ROWS}
225:               total={errorCount}
226:               renderItem={(e, i) => (
227:                 <div key={i} className="mono-xs mb-1">
228:                   <span style={{ color: 'var(--status-critical)' }}>✗</span>{' '}
229:                   {e.spanName}{e.tool ? ` (${e.tool})` : ''}{e.filePath ? ` · ${shortPath(e.filePath)}` : ''}
230:                   {e.errorType && e.errorType !== 'unknown' && <span className="text-muted"> — {e.errorType}</span>}
231:                 </div>
232:               )}
233:             />
234:           </IssueCallout>
235:         )}
236: 
237:         {hallucinationEvals.length > 0 && (
238:           <IssueCallout severity="critical" title={`${plural(hallucinationEvals.length, 'hallucination indicator')} detected`}>
239:             <div className="mb-2">
240:               Evaluations flagging potential hallucination or very low confidence:
241:             </div>
242:             <TruncatedList
243:               items={hallucinationEvals}
244:               max={MAX_HALLUCINATION_ROWS}
245:               renderItem={(e, i) => (
246:                 <div key={i} className="flex-center gap-2-5 mb-1-5">
247:                   <ScoreBadge score={typeof e.scoreValue === 'number' ? e.scoreValue : 0} metricName={e.evaluationName ?? 'hallucination'} />
248:                   <div>
249:                     <div className="mono-xs">{e.evaluationName}</div>
250:                     {e.explanation && (
251:                       <div className="text-muted text-xs" style={{ marginTop: 'var(--space-0-5)' }}>
252:                         {truncateText(e.explanation, 200)}
253:                       </div>
254:                     )}
255:                   </div>
256:                 </div>
257:               )}
258:             />
259:           </IssueCallout>
260:         )}
261: 
262:         {failedEvals.length > 0 && !hallucinationEvals.length && (
263:           <IssueCallout severity="warning" title={`${plural(failedEvals.length, 'evaluation')} marked fail`}>
264:             <TruncatedList
265:               items={failedEvals}
266:               max={MAX_FAILED_EVAL_ROWS}
267:               renderItem={(e, i) => (
268:                 <div key={i} className="mono-xs" style={{ marginBottom: 'var(--space-1)' }}>
269:                   <span className="text-warning">⚠</span>{' '}
270:                   {e.evaluationName} — score {typeof e.scoreValue === 'number' ? e.scoreValue.toFixed(SCORE_DISPLAY_PRECISION) : 'N/A'}
271:                 </div>
272:               )}
273:             />
274:           </IssueCallout>
275:         )}
276: 
277:         {evaluation.errorPropagationTurns > 0 && (
278:           <IssueCallout severity="warning" title={plural(evaluation.errorPropagationTurns, 'error propagation turn')}>
279:             Errors detected in the multi-agent turn sequence may have propagated across agent handoffs.
280:           </IssueCallout>
281:         )}
282:       </Section>
283: 
284:       {/* ── Token Journey ── */}
285:       <Section
286:         title="Token Journey"
287:         badge={maxTokenSnapshot ? `${maxTokenSnapshot.messages} msg · ${fmtBytes(maxTokenSnapshot.outputTokens)} out` : 'no data'}
288:         health="neutral"
289:       >
290:         {tokenProgression.length === 0 ? (
291:           <div className="text-muted text-xs">No token snapshots recorded.</div>
292:         ) : (
293:           <div className="overflow-x-auto">
294:             <table className="mono-xs w-full table-collapse">
295:               <MonoTableHead columns={[
296:                 { label: 'Messages' }, { label: 'Input' }, { label: 'Output' },
297:                 { label: 'Cache Read' }, { label: 'Cache Create' }, { label: 'Model' },
298:               ]} />
299:               <tbody>
300:                 {tokenProgression.map((t, i) => (
301:                   <tr key={i} className="border-b-subtle">
302:                     <td className="cell-pad-wide text-right">{t.messages}</td>
303:                     <td className="cell-pad-wide text-right text-secondary">{fmtBytes(t.inputTokens)}</td>
304:                     <td className="cell-pad-wide text-right text-accent-hover">{fmtBytes(t.outputTokens)}</td>
305:                     <td className="cell-pad-wide text-right text-muted">{fmtBytes(t.cacheRead)}</td>
306:                     <td className="cell-pad-wide text-right text-muted">{fmtBytes(t.cacheCreation)}</td>
307:                     <td className="cell-pad-wide text-right text-muted">{t.model}</td>
308:                   </tr>
309:                 ))}
310:               </tbody>
311:             </table>
312:           </div>
313:         )}
314:       </Section>
315: 
316:       {/* ── Tool Activity ── */}
317:       <Section
318:         title="Tool Activity"
319:         badge={`${totalToolCalls} calls · ${Object.keys(toolUsage).length} tools`}
320:         health="neutral"
321:       >
322:         <FreqBarGrid entries={Object.entries(toolUsage)} max={maxToolCount} />
323: 
324:         {totalMcpCalls > 0 && (
325:           <>
326:             <div className="stat-label" style={{ letterSpacing: 'var(--label-letter-spacing-wide)', margin: 'var(--space-3-5) 0 var(--space-2)' }}>
327:               MCP Tools — {totalMcpCalls} calls
328:             </div>
329:             <FreqBarGrid entries={Object.entries(mcpUsage)} max={maxMcpCount} color="var(--status-healthy)" />
330:           </>
331:         )}
332:       </Section>
333: 
334:       {/* ── Agent Activity ── */}
335:       {agentActivity.length > 0 && (
336:         <Section
337:           title="Agent Activity"
338:           badge={agentActivity.map(a => `${a.agentName} ×${a.invocations}`).join(' · ')}
339:           health={agentActivity.some(a => a.errors > 0) ? 'warn' : 'neutral'}
340:         >
341:           <div className="gap-2-5" style={{ display: 'grid', gridTemplateColumns: `repeat(auto-fill, minmax(${AGENT_CARD_MIN_WIDTH}, 1fr))` }}>
342:             {agentActivity.map(a => (
343:               <div key={a.agentName} style={{
344:                 background: 'var(--bg-elevated)',
345:                 border: `1px solid ${a.errors > 0 ? 'var(--status-warning)' : 'var(--border-subtle)'}`,
346:                 borderRadius: 'var(--radius)',
347:                 padding: 'var(--space-2-5) var(--space-3-5)',
348:               }}>
349:                 <div className="mono-xs mb-1-5 font-semibold">
350:                   {a.agentName}
351:                 </div>
352:                 <div className="flex-wrap gap-3">
353:                   <div>
354:                     <div className="mono text-md font-bold">{a.invocations}</div>
355:                     <div className="stat-label">invocations</div>
356:                   </div>
357:                   {a.errors > 0 && (
358:                     <div>
359:                       <div className="mono text-md font-bold text-warning">{a.errors}</div>
360:                       <div className="stat-label">errors</div>
361:                     </div>
362:                   )}
363:                   <div>
364:                     <div className="mono text-md font-bold">{fmtBytes(a.avgOutputSize)}</div>
365:                     <div className="stat-label">avg output</div>
366:                   </div>
367:                 </div>
368:                 {a.hasRateLimit && (
369:                   <div className="mono mt-2 text-2xs text-warning">
370:                     ⚠ Hit rate limit
371:                   </div>
372:                 )}
373:               </div>
374:             ))}
375:           </div>
376: 
377:           {/* Multi-agent evaluation scores */}
378:           <div className="mt-4">
379:             <AgentScoreSummary handoffScore={handoffScore} avgRelevance={avgRelevance} completeness={completeness} />
380:           </div>
381:         </Section>
382:       )}
383: 
384:       {/* ── Files Accessed ── */}
385:       {fileAccess.length > 0 && (
386:         <Section
387:           title="Files Accessed"
388:           badge={`${fileAccess.length} files · top: ${shortPath(fileAccess[0]?.path ?? '')}`}
389:           health="neutral"
390:         >
391:           <div style={{ columns: `2 ${FILE_ACCESS_COL_MIN}`, columnGap: 'var(--space-8)' }}>
392:             {fileAccess.map(({ path, count }) => (
393:               <div key={path} style={{ breakInside: 'avoid' }}>
394:                 <FreqBar
395:                   label={shortPath(path)}
396:                   count={count}
397:                   max={maxFileCount}
398:                   color="var(--accent)"
399:                 />
400:               </div>
401:             ))}
402:           </div>
403:         </Section>
404:       )}
405: 
406:       {/* ── Git Commits ── */}
407:       {gitCommits.length > 0 && (
408:         <Section
409:           title="Git Commits"
410:           badge={plural(gitCommits.length, 'commit')}
411:           health="ok"
412:         >
413:           <div className="flex-col gap-half">
414:             {gitCommits.map((commit, i) => {
415:               const commitFiles = commit.files?.split(' ') ?? [];
416:               return (
417:                 <details key={i} className="border-b-subtle">
418:                   <summary className="flex-center gap-2-5 cursor-pointer list-none" style={{
419:                     padding: 'var(--space-2) var(--space-1)',
420:                   }}>
421:                     <span className="text-healthy text-2xs shrink-0">●</span>
422:                     <span className="mono-xs font-semibold flex-1">
423:                       {commit.subject}
424:                     </span>
425:                     {commitFiles.length > 0 && (
426:                       <span className="text-2xs text-muted shrink-0">
427:                         {plural(commitFiles.length, 'file')}
428:                       </span>
429:                     )}
430:                   </summary>
431:                   <div style={{ paddingLeft: 'var(--space-5)', paddingBottom: 'var(--space-2-5)' }}>
432:                     {commit.body && (
433:                       <div className="text-secondary text-xs leading-relaxed mb-2" style={{
434:                         fontFamily: 'var(--font-body)',
435:                       }}>
436:                         {commit.body}
437:                       </div>
438:                     )}
439:                     {commitFiles.length > 0 && (
440:                       <div className="mono text-2xs text-muted">
441:                         {commitFiles.map((f, fi) => (
442:                           <div key={fi}>{shortPath(f)}</div>
443:                         ))}
444:                       </div>
445:                     )}
446:                   </div>
447:                 </details>
448:               );
449:             })}
450:           </div>
451:         </Section>
452:       )}
453: 
454:       {/* ── Code Quality ── */}
455:       {codeStructure.length > 0 && (
456:         <Section
457:           title="Code Quality"
458:           badge={`${plural(codeStructure.length, 'file')} analyzed`}
459:           health={codeStructure.some(f => f.score < CODE_QUALITY_WARN_THRESHOLD) ? 'warn' : 'ok'}
460:         >
461:           <div className="overflow-x-auto">
462:             <table className="mono-xs w-full table-collapse">
463:               <MonoTableHead columns={[
464:                 { label: 'File', align: 'left' }, { label: 'Tool', align: 'left' },
465:                 { label: 'Lines' }, { label: 'Exports' }, { label: 'Functions' },
466:                 { label: 'Types' }, { label: 'Score' },
467:               ]} />
468:               <tbody>
469:                 {codeStructure.map((f, i) => (
470:                   <tr key={i} className="border-b-subtle">
471:                     <td className="cell-pad text-secondary">{shortPath(f.file)}</td>
472:                     <td className="cell-pad text-muted">{f.tool}</td>
473:                     <td className="cell-pad text-right">{f.lines}</td>
474:                     <td className="cell-pad text-right text-muted">{f.exports}</td>
475:                     <td className="cell-pad text-right text-muted">{f.functions}</td>
476:                     <td className="cell-pad text-center">{f.hasTypes ? '✓' : '·'}</td>
477:                     <td className="cell-pad text-right font-semibold" style={{ color: SCORE_COLORS[scoreColorBand(f.score)] }}>
478:                       {f.score.toFixed(2)}
479:                     </td>
480:                   </tr>
481:                 ))}
482:               </tbody>
483:             </table>
484:           </div>
485:         </Section>
486:       )}
487: 
488:       {/* ── Span Breakdown ── */}
489:       <Section
490:         title="Span Breakdown"
491:         badge={`${spanCount} total · ${Object.keys(spanBreakdown).length} types`}
492:         health="neutral"
493:       >
494:         <FreqBarGrid entries={Object.entries(spanBreakdown)} max={maxSpanCount} color="var(--border-accent)" />
495:       </Section>
496: 
497:       {/* ── Evaluations ── */}
498:       <Section
499:         title="Evaluations"
500:         badge={evalRows.length > 0 ? plural(evalRows.length, 'result') : 'none'}
501:         health={hallucinationEvals.length > 0 ? 'crit' : failedEvals.length > 0 ? 'warn' : evalRows.length > 0 ? 'ok' : 'neutral'}
502:       >
503:         {evalRows.length === 0 ? (
504:           <div className="text-muted text-xs">
505:             No evaluations recorded for this session.
506:           </div>
507:         ) : (
508:           <EvaluationTable evaluations={evalRows} />
509:         )}
510:       </Section>
511:     </div>
512:   );
513: }   1: @import url('https://fonts.googleapis.com/css2?family=JetBrains+Mono:wght@400;500;600&family=IBM+Plex+Sans:wght@400;500;600&display=swap');
   2: 
   3: :root {
   4:   /* Backgrounds */
   5:   --bg-primary: #0a0e14;
   6:   --bg-card: #131920;
   7:   --bg-elevated: #1a2230;
   8:   --bg-surface: #1f2937;
   9:   --bg-hover: #243044;
  10: 
  11:   /* Borders */
  12:   --border: #2a3a4e;
  13:   --border-subtle: #1e2a3a;
  14:   --border-accent: #3b5278;
  15: 
  16:   /* Text */
  17:   --text-primary: #e2e8f0;
  18:   --text-secondary: #94a3b8;
  19:   --text-muted: #475569;
  20:   --text-on-accent: #ffffff;
  21: 
  22:   /* Status */
  23:   --status-healthy: #26d97f;
  24:   --status-warning: #e5a00d;
  25:   --status-critical: #f04438;
  26:   --status-no-data: #6b7280;
  27:   --status-good: #34d399;
  28:   --status-poor: #f97316;
  29: 
  30:   /* Accent */
  31:   --accent: #3b82f6;
  32:   --accent-hover: #60a5fa;
  33:   --accent-muted: #1e3a5f;
  34: 
  35:   /* Scores (alias shared values to status tokens) */
  36:   --score-excellent: var(--status-healthy);
  37:   --score-good: var(--status-good);
  38:   --score-adequate: var(--status-warning);
  39:   --score-poor: var(--status-poor);
  40:   --score-failing: var(--status-critical);
  41: 
  42:   /* Typography */
  43:   --font-body: 'IBM Plex Sans', -apple-system, BlinkMacSystemFont, sans-serif;
  44:   --font-mono: 'JetBrains Mono', 'SF Mono', Consolas, monospace;
  45: 
  46:   /* Spacing */
  47:   --space-px: 1px;
  48:   --space-0-5: 2px;
  49:   --space-1: 4px;
  50:   --space-1-5: 6px;
  51:   --space-2: 8px;
  52:   --space-2-5: 10px;
  53:   --space-3: 12px;
  54:   --space-3-5: 14px;
  55:   --space-4: 16px;
  56:   --space-5: 20px;
  57:   --space-6: 24px;
  58:   --space-8: 32px;
  59:   --space-16: 64px;
  60: 
  61:   /* Layout */
  62:   --layout-max-width: 1280px;
  63: 
  64:   /* Status tints (bg + border pairs) */
  65:   --bg-status-healthy: #0d1f12;
  66:   --bg-status-warning: #1f1a0d;
  67:   --bg-status-critical: #1f0d0d;
  68:   --border-status-healthy: #1a3a1f;
  69:   --border-status-warning: #3a2f1a;
  70:   --border-status-critical: #3a1a1a;
  71: 
  72:   /* Accent alpha */
  73:   --accent-alpha-10: rgba(59, 130, 246, 0.1);
  74:   --accent-alpha-20: rgba(59, 130, 246, 0.2);
  75: 
  76:   /* Status glow alpha */
  77:   --healthy-alpha-15: rgba(38, 217, 127, 0.15);
  78:   --warning-alpha-15: rgba(229, 160, 13, 0.15);
  79:   --critical-alpha-20: rgba(240, 68, 56, 0.2);
  80:   --critical-alpha-40: rgba(240, 68, 56, 0.4);
  81:   --critical-alpha-60: rgba(240, 68, 56, 0.6);
  82: 
  83:   /* Radii */
  84:   --radius-xs: 2px;
  85:   --radius-bar: 3px;
  86:   --radius-sm: 4px;
  87:   --radius: 6px;
  88:   --radius-lg: 8px;
  89:   --radius-pill: 12px;
  90:   --radius-full: 50%;
  91: 
  92:   /* Border widths */
  93:   --border-width-thick: 2px;
  94:   --border-width-rail: 3px;
  95: 
  96:   /* Font sizes */
  97:   --font-size-2xs: 9px;
  98:   --font-size-xs: 12px;
  99:   --font-size-base: 14px;
 100:   --font-size-md: 16px;
 101:   --font-size-lg: 18px;
 102:   --font-size-xl: 20px;
 103:   --font-size-stat: 22px;
 104:   --font-size-2xl: 24px;
 105:   --font-size-3xl: 36px;
 106: 
 107:   /* Font Weight */
 108:   --bold: 600;
 109:   --light-bold: 500;
 110: 
 111:   /* Label typography */
 112:   --label-letter-spacing: 0.5px;
 113:   --stat-label-letter-spacing: 0.1em;
 114:   --letter-spacing-id: 0.02em;
 115:   --label-letter-spacing-wide: 0.12em;
 116: 
 117:   /* Transitions */
 118:   --transition-fast: 0.15s ease;
 119:   --transition-medium: 0.2s ease;
 120:   --transition-bar: width 0.3s ease;
 121: 
 122:   /* Shadows */
 123:   --shadow-sm: 0 1px 2px rgba(0,0,0,0.3);
 124:   --shadow-glow-healthy: 0 0 12px var(--healthy-alpha-15);
 125:   --shadow-glow-warning: 0 0 12px var(--warning-alpha-15);
 126:   --shadow-glow-critical: 0 0 12px var(--critical-alpha-20);
 127: 
 128: }
 129: 
 130: /* Overflow */
 131: .overflow-x-auto { overflow-x: auto; }
 132: 
 133: /* Interaction */
 134: .select-none { user-select: none; }
 135: 
 136: /* Cursor */
 137: .cursor-pointer { cursor: pointer; }
 138: 
 139: * {
 140:   margin: 0;
 141:   padding: 0;
 142:   box-sizing: border-box;
 143: }
 144: 
 145: /* Shared uppercase label pattern */
 146: .summary-count .label,
 147: .sla-table th,
 148: .cot-summary,
 149: .agreement-grid .ag-header,
 150: .stat-label,
 151: .field-label {
 152:   text-transform: uppercase;
 153:   letter-spacing: var(--label-letter-spacing);
 154: }
 155: 
 156: /* Shared accent link base + hover */
 157: .back-link,
 158: .tooltip-link,
 159: .alert-metric-link {
 160:   color: var(--accent);
 161:   text-decoration: none;
 162: }
 163: .back-link:hover,
 164: .tooltip-link:hover,
 165: .alert-metric-link:hover {
 166:   text-decoration: underline;
 167: }
 168: 
 169: .summary-count { text-align: center; }
 170: .card:hover { border-color: var(--border); }
 171: .trend.stable { color: var(--text-secondary); }
 172: .card.glow-critical { box-shadow: var(--shadow-glow-critical); }
 173: .card.glow-warning { box-shadow: var(--shadow-glow-warning); }
 174: 
 175: body {
 176:   font-family: var(--font-body);
 177:   background: var(--bg-primary);
 178:   color: var(--text-primary);
 179:   line-height: 1.6;
 180:   font-size: var(--font-size-base);
 181:   -webkit-font-smoothing: antialiased;
 182: }
 183: 
 184: @media (prefers-reduced-motion: reduce) {
 185:   *, *::before, *::after {
 186:     animation-duration: 0.01ms !important;
 187:     transition-duration: 0.01ms !important;
 188:   }
 189: }
 190: 
 191: .dashboard-container {
 192:   max-width: var(--layout-max-width);
 193:   margin: 0 auto;
 194:   padding: var(--space-6);
 195: }
 196: 
 197: .metric-grid {
 198:   display: grid;
 199:   grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
 200:   gap: var(--space-4);
 201: }
 202: 
 203: .card {
 204:   background: var(--bg-card);
 205:   border: 1px solid var(--border-subtle);
 206:   border-radius: var(--radius-lg);
 207:   padding: var(--space-5);
 208:   box-shadow: var(--shadow-sm);
 209: }
 210: 
 211: .card-link {
 212:   text-decoration: none;
 213:   color: inherit;
 214:   display: block;
 215: }
 216: 
 217: /* Status color tokens — applied via data-status attribute */
 218: [data-status="healthy"]  { --s-bg: var(--bg-status-healthy);  --s-border: var(--border-status-healthy);  --s-fg: var(--status-healthy); }
 219: [data-status="warning"]  { --s-bg: var(--bg-status-warning);  --s-border: var(--border-status-warning);  --s-fg: var(--status-warning); }
 220: [data-status="critical"] { --s-bg: var(--bg-status-critical); --s-border: var(--border-status-critical); --s-fg: var(--status-critical); }
 221: [data-status="no_data"]  { --s-bg: var(--bg-elevated);         --s-border: var(--border);                  --s-fg: var(--status-no-data); }
 222: [data-status="info"]     { --s-bg: var(--bg-elevated);         --s-border: var(--border);                  --s-fg: var(--text-secondary); }
 223: 
 224: /* Health banner */
 225: .health-banner {
 226:   padding: var(--space-4) var(--space-5);
 227:   border-radius: var(--radius);
 228:   margin-bottom: var(--space-6);
 229:   justify-content: space-between;
 230: }
 231: .health-banner[data-status] { background: var(--s-bg); border: 1px solid var(--s-border); }
 232: 
 233: 
 234: .summary-count .value {
 235:   font-size: var(--font-size-2xl);
 236:   font-weight: var(--bold);
 237:   font-family: var(--font-mono);
 238: }
 239: /* Status badges */
 240: .status-badge {
 241:   gap: var(--space-1-5);
 242:   font-weight: var(--light-bold);
 243:   padding: var(--space-px) var(--space-2);
 244:   border-radius: var(--radius-pill);
 245: }
 246: .status-badge[data-status] { color: var(--s-fg); background: var(--s-bg); }
 247: 
 248: /* Trend indicator */
 249: .trend {
 250:   gap: var(--space-1);
 251:   font-size: var(--font-size-xs);
 252:   font-family: var(--font-mono);
 253: }
 254: .trend.improving { color: var(--status-healthy); }
 255: .trend.degrading { color: var(--status-critical); }
 256: /* Metric card */
 257: .metric-card-header {
 258:   justify-content: space-between;
 259:   margin-bottom: var(--space-3);
 260: }
 261: .metric-card-header h3 {
 262:   font-size: var(--font-size-base);
 263:   font-weight: var(--light-bold);
 264: }
 265: 
 266: .metric-values {
 267:   font-family: var(--font-mono);
 268:   font-size: var(--font-size-xs);
 269: }
 270: .metric-values .primary {
 271:   font-size: var(--font-size-2xl);
 272:   font-weight: var(--bold);
 273:   line-height: 1.2;
 274: }
 275: .metric-values .secondary {
 276:   color: var(--text-secondary);
 277:   margin-top: var(--space-1);
 278: }
 279: 
 280: /* Shared section divider */
 281: .metric-footer,
 282: .pipeline-stats,
 283: .agreement-summary {
 284:   margin-top: var(--space-3);
 285:   padding-top: var(--space-3);
 286:   border-top: 1px solid var(--border-subtle);
 287:   font-size: var(--font-size-xs);
 288:   color: var(--text-secondary);
 289: }
 290: 
 291: .metric-footer {
 292:   justify-content: space-between;
 293:   border-top-color: var(--border);
 294: }
 295: 
 296: /* Alerts */
 297: .alert-list {
 298:   list-style: none;
 299: }
 300: .alert-item {
 301:   padding: var(--space-3) var(--space-4);
 302:   border-left: 3px solid;
 303:   background: var(--bg-card);
 304:   margin-bottom: var(--space-2);
 305:   border-radius: 0 var(--radius) var(--radius) 0;
 306: }
 307: .alert-item[data-status] { border-left-color: var(--s-fg); }
 308: .alert-item .alert-meta,
 309: .alert-item .remediation {
 310:   margin-top: var(--space-1);
 311: }
 312: .alert-item .remediation { color: var(--accent); }
 313: 
 314: /* Shared table base */
 315: .data-table { width: 100%; border-collapse: collapse; }
 316: .data-table th,
 317: .data-table td { border-bottom: 1px solid var(--border); }
 318: .data-table th {
 319:   font-size: var(--font-size-xs);
 320:   text-align: left;
 321:   color: var(--text-secondary);
 322:   font-weight: var(--light-bold);
 323: }
 324: 
 325: /* SLA table */
 326: .sla-table { font-size: var(--font-size-base); }
 327: .sla-table th,
 328: .sla-table td { padding: var(--space-2) var(--space-3); }
 329: 
 330: /* Histogram */
 331: .histogram {
 332:   display: flex;
 333:   align-items: flex-end;
 334:   gap: var(--space-px);
 335:   height: 120px;
 336:   padding: var(--space-2) 0;
 337: }
 338: .histogram-bar {
 339:   flex: 1;
 340:   background: var(--accent);
 341:   border-radius: var(--radius-xs) var(--radius-xs) 0 0;
 342:   min-height: var(--space-px);
 343:   position: relative;
 344: }
 345: .histogram-bar:hover {
 346:   opacity: 0.8;
 347: }
 348: /* Shared tooltip popup base */
 349: .histogram-bar .tooltip,
 350: .score-badge-tooltip {
 351:   display: none;
 352:   position: absolute;
 353:   left: 50%;
 354:   transform: translateX(-50%);
 355:   font-size: var(--font-size-xs);
 356: }
 357: 
 358: .histogram-bar .tooltip {
 359:   bottom: 100%;
 360:   padding: var(--space-1) var(--space-2);
 361:   border-radius: var(--radius-sm);
 362:   white-space: nowrap;
 363:   z-index: 10;
 364: }
 365: .histogram-bar:hover .tooltip {
 366:   display: block;
 367: }
 368: .histogram-labels {
 369:   display: flex;
 370:   justify-content: space-between;
 371:   font-size: var(--font-size-xs);
 372:   color: var(--text-muted);
 373:   font-family: var(--font-mono);
 374: }
 375: 
 376: /* Evaluation detail table */
 377: .eval-table {
 378:   font-size: var(--font-size-xs);
 379: }
 380: .eval-table th,
 381: .eval-table td {
 382:   padding: var(--space-1-5) var(--space-2-5);
 383: }
 384: .eval-table td {
 385:   font-family: var(--font-mono);
 386: }
 387: .eval-table .explanation {
 388:   font-family: inherit;
 389:   color: var(--text-secondary);
 390:   max-width: 300px;
 391: }
 392: .eval-table tbody tr:hover,
 393: .eval-table .eval-row-expanded {
 394:   background: var(--bg-elevated);
 395: }
 396: .eval-table .eval-expanded-panel td {
 397:   padding: 0 var(--space-2-5) var(--space-2-5);
 398: }
 399: .eval-expanded-content {
 400:   background: var(--bg-elevated);
 401:   border-radius: var(--radius);
 402:   padding: var(--space-4);
 403:   animation: fade-in var(--transition-fast);
 404: }
 405: 
 406: /* Expanded-panel section padding */
 407: .pad-panel-section { padding: var(--space-2-5) 0 var(--space-2); }
 408: .pad-panel-sparse  { padding: var(--space-2-5) 0 var(--space-1); }
 409: 
 410: /* Shared ghost button reset */
 411: .tab-btn,
 412: .period-btn {
 413:   background: none;
 414:   border: none;
 415:   color: var(--text-secondary);
 416:   cursor: pointer;
 417: }
 418: 
 419: /* Tabs / Role selector */
 420: .tab-nav {
 421:   display: flex;
 422:   gap: var(--space-1);
 423:   margin-bottom: var(--space-6);
 424:   border-bottom: 1px solid var(--border);
 425:   padding-bottom: 0;
 426: }
 427: .tab-btn {
 428:   padding: var(--space-2) var(--space-4);
 429:   font-size: var(--font-size-base);
 430:   border-bottom: 2px solid transparent;
 431:   margin-bottom: -1px;
 432:   transition: color var(--transition-fast), border-color var(--transition-fast);
 433: }
 434: .tab-btn:hover {
 435:   color: var(--text-primary);
 436: }
 437: .tab-btn[aria-selected="true"] {
 438:   color: var(--text-primary);
 439:   border-bottom-color: var(--accent);
 440: }
 441: 
 442: /* Period selector */
 443: .period-selector {
 444:   display: inline-flex;
 445:   gap: var(--space-1);
 446:   background: var(--bg-elevated);
 447:   border-radius: var(--radius);
 448:   padding: var(--space-px);
 449: }
 450: .period-btn {
 451:   padding: var(--space-1) var(--space-3);
 452:   border-radius: var(--radius);
 453:   font-size: var(--font-size-xs);
 454:   font-family: var(--font-body);
 455: }
 456: .period-btn.active {
 457:   background: var(--bg-card);
 458:   color: var(--text-primary);
 459: }
 460: 
 461: /* Header */
 462: .header {
 463:   justify-content: space-between;
 464:   margin-bottom: var(--space-6);
 465: }
 466: .header h1 {
 467:   font-size: var(--font-size-xl);
 468:   font-weight: var(--bold);
 469: }
 470: 
 471: /* Loading skeleton */
 472: .skeleton {
 473:   background: linear-gradient(90deg, var(--bg-card) 25%, var(--bg-elevated) 50%, var(--bg-card) 75%);
 474:   background-size: 200% 100%;
 475:   animation: skeleton-pulse 1.5s ease-in-out infinite;
 476:   border-radius: var(--radius);
 477: }
 478: @keyframes skeleton-pulse {
 479:   0% { background-position: 200% 0; }
 480:   100% { background-position: -200% 0; }
 481: }
 482: 
 483: /* Empty state */
 484: .empty-state {
 485:   text-align: center;
 486:   padding: var(--space-16) var(--space-6);
 487:   color: var(--text-secondary);
 488: }
 489: .empty-state h2 {
 490:   color: var(--text-primary);
 491:   margin-bottom: var(--space-2);
 492: }
 493: .empty-state code {
 494:   background: var(--bg-elevated);
 495:   padding: var(--space-px) var(--space-1-5);
 496:   border-radius: var(--radius-sm);
 497:   font-family: var(--font-mono);
 498:   font-size: var(--font-size-xs);
 499: }
 500: 
 501: /* Back link */
 502: .back-link {
 503:   font-size: var(--font-size-xs);
 504:   gap: var(--space-1);
 505:   margin-bottom: var(--space-4);
 506: }
 507: 
 508: /* Error state */
 509: .error-state {
 510:   background: var(--bg-status-critical);
 511:   border: 1px solid var(--border-status-critical);
 512:   border-radius: var(--radius);
 513:   padding: var(--space-6);
 514:   text-align: center;
 515: }
 516: .error-state h2 {
 517:   color: var(--status-critical);
 518:   margin-bottom: var(--space-2);
 519: }
 520: .error-state .error-actions {
 521:   display: flex;
 522:   gap: var(--space-2);
 523:   margin-top: var(--space-3);
 524:   justify-content: center;
 525: }
 526: .error-state .error-actions button,
 527: .error-state .error-actions a {
 528:   padding: var(--space-1-5) var(--space-4);
 529:   cursor: pointer;
 530: }
 531: 
 532: /* Section headings */
 533: .section-heading {
 534:   font-size: var(--font-size-md);
 535:   font-weight: var(--bold);
 536:   margin-bottom: var(--space-4);
 537:   margin-top: var(--space-8);
 538: }
 539: 
 540: /* Session detail — stat item, stat value, stat label, vitals divider, frequency grid */
 541: .stat-item {
 542:   flex: 1 1 100px;
 543:   min-width: 80px;
 544:   text-align: center;
 545: }
 546: 
 547: .stat-value {
 548:   font-size: var(--font-size-stat);
 549:   line-height: 1.1;
 550: }
 551: 
 552: .stat-label {
 553:   font-size: var(--font-size-xs);
 554:   font-family: var(--font-mono);
 555:   color: var(--text-muted);
 556:   letter-spacing: var(--stat-label-letter-spacing);
 557:   margin-top: var(--space-px);
 558: }
 559: 
 560: .freq-bar-row {
 561:   display: grid;
 562:   grid-template-columns: 160px 1fr 36px;
 563:   align-items: center;
 564:   gap: var(--space-2-5);
 565:   margin-bottom: var(--space-1-5);
 566: }
 567: 
 568: .vitals-divider {
 569:   width: 1px;
 570:   background: var(--border-subtle);
 571:   margin: 0 var(--space-2);
 572:   align-self: stretch;
 573: }
 574: 
 575: .freq-grid {
 576:   display: grid;
 577:   grid-template-columns: repeat(auto-fill, minmax(340px, 1fr));
 578:   gap: 0 var(--space-8);
 579: }
 580: 
 581: /* View sections */
 582: .view-section {
 583:   margin-bottom: var(--space-8);
 584: }
 585: 
 586: /* Refetch indicator */
 587: .refetch-indicator {
 588:   position: fixed;
 589:   top: var(--space-4);
 590:   right: var(--space-4);
 591:   padding: var(--space-2) var(--space-4);
 592:   border-radius: var(--radius);
 593:   font-size: var(--font-size-xs);
 594:   color: var(--text-secondary);
 595:   z-index: 1000;
 596:   animation: fade-in var(--transition-fast);
 597: }
 598: 
 599: @keyframes fade-in {
 600:   from { opacity: 0; transform: translateY(-8px); }
 601:   to { opacity: 1; transform: translateY(0); }
 602: }
 603: 
 604: @keyframes toxicPulse {
 605:   0%, 100% { box-shadow: 0 0 0 0 var(--critical-alpha-40); }
 606:   50% { box-shadow: 0 0 6px 2px var(--critical-alpha-60); }
 607: }
 608: 
 609: /* Score badge tooltip */
 610: .score-badge-wrapper {
 611:   position: relative;
 612:   cursor: default;
 613: }
 614: .score-badge-tooltip {
 615:   bottom: calc(100% + var(--space-2));
 616:   border-radius: var(--radius);
 617:   padding: var(--space-2-5) var(--space-3);
 618:   min-width: 200px;
 619:   max-width: 300px;
 620:   z-index: 20;
 621:   white-space: normal;
 622:   animation: fade-in var(--transition-fast);
 623: }
 624: .score-badge-wrapper:hover .score-badge-tooltip,
 625: .score-badge-wrapper:focus-within .score-badge-tooltip {
 626:   display: block;
 627: }
 628: .tooltip-row {
 629:   display: flex;
 630:   justify-content: space-between;
 631:   gap: var(--space-3);
 632:   padding: var(--space-px) 0;
 633:   color: var(--text-primary);
 634: }
 635: .tooltip-link {
 636:   display: block;
 637:   margin-top: var(--space-2);
 638:   padding-top: var(--space-1-5);
 639:   border-top: 1px solid var(--border);
 640: }
 641: 
 642: /* Chain of thought panel */
 643: .cot-panel {
 644:   margin-top: var(--space-1);
 645: }
 646: .cot-summary {
 647:   color: var(--text-secondary);
 648:   cursor: pointer;
 649:   padding: var(--space-1) 0;
 650:   list-style: none;
 651: }
 652: .cot-summary::-webkit-details-marker {
 653:   display: none;
 654: }
 655: .cot-summary::before {
 656:   content: '\25B6';
 657:   display: inline-block;
 658:   margin-right: var(--space-1-5);
 659:   font-size: var(--font-size-2xs);
 660:   transition: transform var(--transition-fast);
 661: }
 662: details[open] > .cot-summary::before {
 663:   transform: rotate(90deg);
 664: }
 665: .cot-content {
 666:   font-size: var(--font-size-xs);
 667:   color: var(--text-primary);
 668:   line-height: 1.6;
 669:   padding: var(--space-2) 0 var(--space-1);
 670: }
 671: 
 672: /* Evaluation detail page */
 673: .eval-detail-header {
 674:   margin-bottom: var(--space-6);
 675: }
 676: .eval-detail-meta {
 677:   gap: var(--space-4);
 678:   margin-top: var(--space-2);
 679: }
 680: .eval-detail-card {
 681:   margin-bottom: var(--space-4);
 682: }
 683: 
 684: .eval-summary-card.card:hover {
 685:   border-color: var(--accent);
 686: }
 687: 
 688: /* Compound alert card */
 689: .alert-compound {
 690:   border-left-width: var(--space-1);
 691:   background: var(--bg-elevated);
 692: }
 693: .alert-related {
 694:   flex-wrap: wrap;
 695:   gap: var(--space-2);
 696:   margin-top: var(--space-2);
 697: }
 698: .alert-metric-link {
 699:   font-family: var(--font-mono);
 700:   padding: var(--space-px) var(--space-2);
 701:   border-radius: var(--radius-pill);
 702:   background: var(--accent-alpha-10);
 703: }
 704: .alert-metric-link:hover {
 705:   background: var(--accent-alpha-20);
 706: }
 707: .remediation-list {
 708:   margin-top: var(--space-2);
 709:   padding-left: var(--space-5);
 710:   color: var(--accent);
 711: }
 712: .remediation-list li {
 713:   margin-bottom: var(--space-1);
 714: }
 715: .threshold-bar {
 716:   position: relative;
 717:   height: var(--space-1-5);
 718:   background: var(--bg-card);
 719:   border-radius: var(--radius-bar);
 720:   margin-top: var(--space-2);
 721:   overflow: visible;
 722: }
 723: /* Shared animated bar fill */
 724: .threshold-bar-fill,
 725: .variance-bar-fill {
 726:   height: 100%;
 727:   transition: var(--transition-bar);
 728: }
 729: .threshold-bar-fill { border-radius: var(--radius-bar); }
 730: .variance-bar-fill  { border-radius: var(--radius-xs); }
 731: .threshold-bar-marker {
 732:   position: absolute;
 733:   top: -3px;
 734:   width: 2px;
 735:   height: 12px;
 736:   background: var(--text-primary);
 737:   border-radius: calc(var(--radius-xs) / 2);
 738:   transform: translateX(-1px);
 739: }
 740: 
 741: /* Pipeline health stats in HealthOverview */
 742: .pipeline-stat {
 743:   gap: var(--space-1);
 744: }
 745: .pipeline-stat .stat-value {
 746:   font-family: var(--font-mono);
 747:   color: var(--text-primary);
 748:   font-weight: var(--light-bold);
 749: }
 750: 
 751: /* Worst explanation preview on MetricCard */
 752: .metric-worst {
 753:   font-size: var(--font-size-xs);
 754:   color: var(--text-muted);
 755:   margin-top: var(--space-2);
 756:   line-height: 1.4;
 757: }
 758: .metric-worst .worst-score {
 759:   color: var(--score-failing);
 760:   font-family: var(--font-mono);
 761:   font-weight: var(--light-bold);
 762: }
 763: 
 764: /* Provenance panel */
 765: .provenance-grid,
 766: .agreement-grid {
 767:   display: grid;
 768:   gap: var(--space-1) var(--space-4);
 769:   font-family: var(--font-mono);
 770:   font-size: var(--font-size-xs);
 771: }
 772: .provenance-grid { grid-template-columns: auto 1fr; }
 773: .provenance-grid .prov-label {
 774:   color: var(--text-secondary);
 775:   font-family: var(--font-body);
 776:   white-space: nowrap;
 777: }
 778: .provenance-grid .prov-value {
 779:   color: var(--text-primary);
 780:   word-break: break-all;
 781: }
 782: .provenance-actions {
 783:   display: flex;
 784:   gap: var(--space-2);
 785:   margin-top: var(--space-3);
 786: }
 787: .provenance-actions button {
 788:   background: var(--bg-surface);
 789:   border: 1px solid var(--border);
 790:   color: var(--accent);
 791:   padding: var(--space-1) var(--space-3);
 792:   border-radius: var(--radius-sm);
 793:   cursor: pointer;
 794:   font-family: var(--font-body);
 795: }
 796: .provenance-actions button:hover {
 797:   background: var(--bg-hover);
 798:   border-color: var(--border-accent);
 799: }
 800: 
 801: /* Confidence panel */
 802: .confidence-header {
 803:   gap: var(--space-2);
 804:   margin-bottom: var(--space-3);
 805: }
 806: .confidence-method {
 807:   font-family: var(--font-mono);
 808:   font-size: var(--font-size-xs);
 809:   color: var(--text-muted);
 810: }
 811: .agreement-grid { grid-template-columns: 1fr auto auto; }
 812: .agreement-grid .ag-header {
 813:   color: var(--text-muted);
 814:   font-size: var(--font-size-xs);
 815:   font-family: var(--font-body);
 816:   padding-bottom: var(--space-1);
 817:   border-bottom: 1px solid var(--border-subtle);
 818: }
 819: .agreement-summary .summary-value {
 820:   font-family: var(--font-mono);
 821:   color: var(--text-primary);
 822: }
 823: .variance-bar {
 824:   gap: var(--space-2);
 825: }
 826: .variance-bar-track {
 827:   flex: 1;
 828:   height: var(--space-1);
 829:   background: var(--bg-surface);
 830:   border-radius: var(--radius-xs);
 831:   overflow: hidden;
 832: }
 833: 
 834: /* Mini progress bar — track + fill */
 835: .mini-bar {
 836:   height: var(--bar-h, 4px);
 837:   background: var(--bg-surface);
 838:   border-radius: var(--radius-xs);
 839:   overflow: hidden;
 840: }
 841: .mini-bar-fill {
 842:   height: 100%;
 843:   border-radius: var(--radius-xs);
 844:   transition: var(--transition-bar);
 845: }
 846: 
 847: /* Empty card state — card with muted placeholder text */
 848: .card--empty {
 849:   padding: var(--space-4);
 850:   color: var(--text-muted);
 851: }
 852: 
 853: /* Monospace utilities */
 854: .mono      { font-family: var(--font-mono); }
 855: .mono-2xs  { font-family: var(--font-mono); font-size: var(--font-size-2xs); }
 856: .mono-xs   { font-family: var(--font-mono); font-size: var(--font-size-xs); }
 857: .mono-base { font-family: var(--font-mono); font-size: var(--font-size-base); }
 858: .mono-md   { font-family: var(--font-mono); font-size: var(--font-size-md); }
 859: .mono-lg   { font-family: var(--font-mono); font-size: var(--font-size-lg); }
 860: .mono-xl   { font-family: var(--font-mono); font-size: var(--font-size-xl); }
 861: .mono-2xl  { font-family: var(--font-mono); font-size: var(--font-size-2xl); }
 862: 
 863: /* Font size */
 864: .text-2xs  { font-size: var(--font-size-2xs); }
 865: .text-xs   { font-size: var(--font-size-xs); }
 866: .text-base { font-size: var(--font-size-base); }
 867: .text-md   { font-size: var(--font-size-md); }
 868: .text-lg   { font-size: var(--font-size-lg); }
 869: .text-xl   { font-size: var(--font-size-xl); }
 870: .text-2xl  { font-size: var(--font-size-2xl); }
 871: 
 872: /* Text color utilities */
 873: .text-secondary    { color: var(--text-secondary); }
 874: .text-muted        { color: var(--text-muted); }
 875: .text-accent       { color: var(--accent); }
 876: .text-accent-hover { color: var(--accent-hover); }
 877: 
 878: /* Flex layout */
 879: .d-flex         { display: flex; }
 880: .d-grid         { display: grid; }
 881: .d-inline-block { display: inline-block; }
 882: .flex-center    { display: flex; align-items: center; }
 883: .align-start    { align-items: flex-start; }
 884: 
 885: /* Text transform */
 886: .uppercase { text-transform: uppercase; letter-spacing: var(--label-letter-spacing); }
 887: .font-semibold { font-weight: var(--bold); }
 888: 
 889: /* Chip / pill */
 890: .chip { padding: var(--space-px) var(--space-1-5); border-radius: var(--radius-pill); }
 891: 
 892: /* Gap */
 893: .gap-half { gap: var(--space-px); }
 894: .gap-1    { gap: var(--space-1); }
 895: .gap-1-5  { gap: var(--space-1-5); }
 896: .gap-2    { gap: var(--space-2); }
 897: .gap-2-5  { gap: var(--space-2-5); }
 898: .gap-3    { gap: var(--space-3); }
 899: .gap-4    { gap: var(--space-4); }
 900: .gap-5    { gap: var(--space-5); }
 901: .gap-6    { gap: var(--space-6); }
 902: .gap-8    { gap: var(--space-8); }
 903: .gap-16   { gap: var(--space-16); }
 904: 
 905: /* Width */
 906: .w-full   { width: 100%; }
 907: .min-w-120 { min-width: 120px; }
 908: 
 909: /* Margin */
 910: .m-0    { margin: 0; }
 911: .ml-auto { margin-left: auto; }
 912: 
 913: /* Margin-bottom */
 914: .mb-0   { margin-bottom: 0; }
 915: .mb-1   { margin-bottom: var(--space-1); }
 916: .mb-1-5 { margin-bottom: var(--space-1-5); }
 917: .mb-2   { margin-bottom: var(--space-2); }
 918: .mb-2-5 { margin-bottom: var(--space-2-5); }
 919: .mb-3   { margin-bottom: var(--space-3); }
 920: .mb-4   { margin-bottom: var(--space-4); }
 921: .mb-5   { margin-bottom: var(--space-5); }
 922: .mb-6   { margin-bottom: var(--space-6); }
 923: 
 924: /* Margin-top */
 925: .mt-1   { margin-top: var(--space-1); }
 926: .mt-2   { margin-top: var(--space-2); }
 927: .mt-3   { margin-top: var(--space-3); }
 928: .mt-4   { margin-top: var(--space-4); }
 929: 
 930: /* Padding */
 931: .p-4    { padding: var(--space-4); }
 932: .p-6    { padding: var(--space-6); }
 933: 
 934: /* Text align */
 935: .text-center { text-align: center; }
 936: .text-right  { text-align: right; }
 937: .text-left   { text-align: left; }
 938: 
 939: /* Flex */
 940: .flex-wrap          { display: flex; flex-wrap: wrap; }
 941: .flex-col           { display: flex; flex-direction: column; }
 942: .inline-flex-center { display: inline-flex; align-items: center; }
 943: .shrink-0           { flex-shrink: 0; }
 944: .flex-1             { flex: 1; }
 945: .justify-between    { justify-content: space-between; }
 946: .justify-center     { justify-content: center; }
 947: 
 948: /* Display */
 949: .contents { display: contents; }
 950: 
 951: /* Opacity */
 952: .opacity-50 { opacity: 0.5; }
 953: 
 954: /* List */
 955: .list-none { list-style: none; }
 956: 
 957: /* Vertical align */
 958: .valign-middle { vertical-align: middle; }
 959: 
 960: /* Table */
 961: .table-collapse { border-collapse: collapse; }
 962: 
 963: /* Accessibility */
 964: .sr-only {
 965:   position: absolute;
 966:   width: 1px;
 967:   height: 1px;
 968:   overflow: hidden;
 969:   clip: rect(0, 0, 0, 0);
 970:   white-space: nowrap;
 971: }
 972: 
 973: /* Typography */
 974: .font-medium { font-weight: var(--light-bold); }
 975: .font-bold   { font-weight: 700; }
 976: .italic      { font-style: italic; }
 977: .nowrap      { white-space: nowrap; }
 978: .truncate  { overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }
 979: .break-all { word-break: break-all; }
 980: .leading-relaxed { line-height: 1.6; }
 981: 
 982: /* Button reset */
 983: .btn-reset { background: none; border: none; padding: 0; }
 984: 
 985: /* Expand chevron */
 986: .expand-chevron {
 987:   display: inline-block;
 988:   transition: transform var(--transition-fast);
 989:   line-height: 1;
 990: }
 991: 
 992: /* Status colors */
 993: .text-healthy  { color: var(--status-healthy); }
 994: .text-warning  { color: var(--status-warning); }
 995: .text-critical { color: var(--status-critical); }
 996: .text-primary  { color: var(--text-primary); }
 997: 
 998: /* Surface */
 999: .surface-elevated { background: var(--bg-elevated); border: 1px solid var(--border); }
1000: 
1001: /* Link */
1002: .link-accent { color: var(--accent); text-decoration: none; }
1003: 
1004: /* Table cells */
1005: .cell-pad      { padding: var(--space-1) var(--space-2-5); }
1006: .cell-pad-wide { padding: var(--space-1) var(--space-3); }
1007: 
1008: /* Border */
1009: .border-b        { border-bottom: 1px solid var(--border); }
1010: .border-b-subtle { border-bottom: 1px solid var(--border-subtle); }
1011: .border-t        { border-top: 1px solid var(--border); }
1012: 
1013: /* Compound: chip with elevated bg + subtle border */
1014: .chip-badge {
1015:   background: var(--bg-elevated);
1016:   border: 1px solid var(--border-subtle);
1017: }
1018: 
1019: /* Compound: chip with accent tint bg */
1020: .chip-accent {
1021:   background: var(--accent-alpha-10);
1022:   color: var(--accent);
1023: }
1024: 
1025: /* Compound: colored dot indicators */
1026: .dot-sm {
1027:   width: 8px;
1028:   height: 8px;
1029:   border-radius: 50%;
1030:   display: inline-block;
1031:   flex-shrink: 0;
1032: }
1033: .dot-xs {
1034:   width: 6px;
1035:   height: 6px;
1036:   border-radius: 50%;
1037:   display: inline-block;
1038:   flex-shrink: 0;
1039: }
1040: 
1041: /* Compound: warning badge pill */
1042: .badge-warning {
1043:   color: var(--status-warning);
1044:   background: var(--bg-status-warning);
1045:   padding: var(--space-px) var(--space-1-5);
1046:   border-radius: var(--radius-pill);
1047: }
1048: 
1049: /* Compound: section rail panel (bg-card + left border rail) */
1050: .section-rail {
1051:   background: var(--bg-card);
1052:   border-left: 3px solid var(--section-rail-color, var(--border-accent));
1053: }
